                for (column, value) in columns.iter().zip(row_values) {
                    row.insert(
                        column.clone(),
                        value
                            .as_ref()
                            .map_or(Ok(serde_json::Value::Null), stat_value_to_json_value)?,
                    );
                }
                let line = serde_json::Value::Object(row).to_string();
