#[cfg(feature = "vortex-local-primitives")]
fn fast_in_list_row_indices_from_typed_values<T, F>(
    values: &[T],
    row_nulls: Option<&[bool]>,
    null_matches: bool,
    negated: bool,
    mut value_matches: F,
) -> Result<Vec<usize>>
where
    T: Copy,
    F: FnMut(T) -> bool,
{
    validate_optional_row_nulls_len(values.len(), row_nulls)?;
    let mut selected = Vec::new();
    for (row_index, value) in values.iter().copied().enumerate() {
        let matched = if row_nulls
            .and_then(|nulls| nulls.get(row_index))
            .copied()
            .unwrap_or(false)
        {
            null_matches
        } else {
            value_matches(value)
        };
        if if negated { !matched } else { matched } {
            selected.push(row_index);
        }
    }
    Ok(selected)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_dictionary_in_list_row_indices_from_accessor(
    row_ids: &[u32],
    dictionary_values: &[std::sync::Arc<str>],
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    column: &str,
    values: &[StatValue],
    negated: bool,
) -> Result<Vec<usize>> {
    let (dictionary_matches, null_matches) = utf8_dictionary_in_list_match_flags(
        row_ids.len(),
        dictionary_values,
        value_nulls,
        row_nulls,
        column,
        values,
    )?;
    if aggregate_utf8_dictionary_value_nulls_are_absent(value_nulls, row_nulls) {
        return fast_non_null_utf8_dictionary_row_indices_from_in_list_flags(
            row_ids,
            &dictionary_matches,
            negated,
            column,
        );
    }
    let value_selection_flags: Vec<bool> = dictionary_matches
        .iter()
        .map(|matched| if negated { !*matched } else { *matched })
        .collect();
    let null_selected = if negated { !null_matches } else { null_matches };
    if let Some(proved_selection) = utf8_dictionary_nullable_row_indices_from_selection_proof(
        row_ids,
        dictionary_values.len(),
        value_nulls,
        row_nulls,
        &value_selection_flags,
        null_selected,
    )? {
        return Ok(proved_selection);
    }
    let mut selected = Vec::new();
    for row_index in 0..row_ids.len() {
        let matched = if aggregate_utf8_dictionary_row_has_null(
            row_ids,
            dictionary_values.len(),
            value_nulls,
            row_nulls,
            row_index,
        )? {
            null_matches
        } else {
            let index = aggregate_utf8_dictionary_code_index(row_ids, row_index)?;
            *dictionary_matches.get(index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex IN-list dictionary row index referenced a missing match flag; no fallback execution was attempted"
                        .to_string(),
                )
            })?
        };
        if if negated { !matched } else { matched } {
            selected.push(row_index);
        }
    }
    Ok(selected)
}

#[cfg(feature = "vortex-local-primitives")]
fn utf8_dictionary_nullable_row_indices_from_selection_proof(
    row_ids: &[u32],
    values_len: usize,
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    value_selection_flags: &[bool],
    null_selected: bool,
) -> Result<Option<Vec<usize>>> {
    aggregate_utf8_dictionary_value_nulls_match_len(
        values_len,
        value_nulls,
        row_ids.len(),
        row_nulls,
    )?;
    if value_selection_flags.len() != values_len {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex UTF-8 dictionary selection proof width did not match values; no fallback execution was attempted"
                .to_string(),
        ));
    }

    let mut selected_non_null_values = 0usize;
    let mut total_non_null_values = 0usize;
    for (value_index, selected) in value_selection_flags.iter().copied().enumerate() {
        if value_nulls
            .and_then(|nulls| nulls.get(value_index))
            .copied()
            .unwrap_or(false)
        {
            continue;
        }
        total_non_null_values = total_non_null_values.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex UTF-8 dictionary non-null value count overflowed usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        if selected {
            selected_non_null_values =
                selected_non_null_values.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex UTF-8 dictionary selected value count overflowed usize; no fallback execution was attempted"
                            .to_string(),
                    )
                })?;
        }
    }

    let all_non_null_values_selected = selected_non_null_values == total_non_null_values;
    let no_non_null_values_selected = selected_non_null_values == 0;
    if all_non_null_values_selected {
        return if null_selected {
            Ok(Some((0..row_ids.len()).collect()))
        } else {
            Ok(Some(fast_utf8_dictionary_null_row_indices_from_accessor(
                row_ids,
                values_len,
                value_nulls,
                row_nulls,
                false,
            )?))
        };
    }
    if no_non_null_values_selected {
        return if null_selected {
            Ok(Some(fast_utf8_dictionary_null_row_indices_from_accessor(
                row_ids,
                values_len,
                value_nulls,
                row_nulls,
                true,
            )?))
        } else {
            Ok(Some(Vec::new()))
        };
    }
    Ok(None)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_non_null_utf8_dictionary_row_indices_from_in_list_flags(
    row_ids: &[u32],
    dictionary_matches: &[bool],
    negated: bool,
    column: &str,
) -> Result<Vec<usize>> {
    let selects_value = |matched: &bool| if negated { !*matched } else { *matched };
    if dictionary_matches
        .iter()
        .all(|matched| !selects_value(matched))
    {
        return Ok(Vec::new());
    }
    if dictionary_matches.iter().all(selects_value) {
        return Ok((0..row_ids.len()).collect());
    }
    let mut selected = Vec::new();
    for (row_index, id) in row_ids.iter().copied().enumerate() {
        let value_index = usize::try_from(id).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary IN-list code for column '{column}' exceeded usize: {error}; no fallback execution was attempted"
            ))
        })?;
        let Some(&matched) = dictionary_matches.get(value_index) else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary IN-list match flag for column '{column}' was missing; no fallback execution was attempted"
            )));
        };
        if if negated { !matched } else { matched } {
            selected.push(row_index);
        }
    }
    Ok(selected)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_non_null_utf8_dictionary_match_count_from_flags(
    row_ids: &[u32],
    value_matches: &[bool],
    context: &str,
) -> Result<usize> {
    if !value_matches.iter().any(|matched| *matched) {
        return Ok(0);
    }
    if value_matches.iter().all(|matched| *matched) {
        return Ok(row_ids.len());
    }
    let mut selected = 0usize;
    for id in row_ids {
        let value_index = usize::try_from(*id).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary {context} code exceeded usize: {error}; no fallback execution was attempted"
            ))
        })?;
        let Some(&matched) = value_matches.get(value_index) else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary {context} match flag was missing; no fallback execution was attempted"
            )));
        };
        if matched {
            selected = selected.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex non-null dictionary {context} selected count overflowed usize"
                ))
            })?;
        }
    }
    Ok(selected)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_non_null_utf8_dictionary_match_count_from_flags_masked(
    row_ids: &[u32],
    value_matches: &[bool],
    mask: &vortex::mask::Mask,
    context: &str,
) -> Result<usize> {
    if mask.len() != row_ids.len() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex non-null dictionary {context} mask length did not match rows; no fallback execution was attempted"
        )));
    }
    if mask.all_false() {
        return Ok(0);
    }
    if mask.all_true() {
        return fast_non_null_utf8_dictionary_match_count_from_flags(
            row_ids,
            value_matches,
            context,
        );
    }
    if !value_matches.iter().any(|matched| *matched) {
        return Ok(0);
    }
    if value_matches.iter().all(|matched| *matched) {
        return Ok(mask.true_count());
    }
    let mut selected = 0usize;
    for (source_row_index, mask_selected) in mask.iter().enumerate() {
        if !mask_selected {
            continue;
        }
        let id = row_ids.get(source_row_index).copied().ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary {context} row index was out of bounds; no fallback execution was attempted"
            ))
        })?;
        let value_index = usize::try_from(id).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary {context} code exceeded usize: {error}; no fallback execution was attempted"
            ))
        })?;
        let Some(&matched) = value_matches.get(value_index) else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex non-null dictionary {context} match flag was missing; no fallback execution was attempted"
            )));
        };
        if matched {
            selected = selected.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex non-null dictionary {context} selected count overflowed usize"
                ))
            })?;
        }
    }
    Ok(selected)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_in_list_accessor_row_matches(
    accessor: &AggregateDirectColumnAccessor,
    column: &str,
    values: &[StatValue],
    row_index: usize,
    negated: bool,
) -> Result<bool> {
    let current = aggregate_direct_stat_value(accessor, row_index)?;
    let matched = values.iter().any(|value| {
        coerce_rewrite_value_for_column(Some(column), &current, value)
            .ok()
            .is_some_and(|value| stat_value_equal(&current, &value))
    });
    Ok(if negated { !matched } else { matched })
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_contains_count_from_array(
    target: &vortex::array::ArrayRef,
    needle: &str,
    negated: bool,
) -> Result<Option<usize>> {
    use vortex::array::VortexSessionExecute as _;
    use vortex::array::arrays::Chunked;
    use vortex::array::arrays::Filter;
    use vortex::array::arrays::chunked::ChunkedArrayExt as _;
    use vortex::array::arrays::varbinview::VarBinView;
    use vortex::array::arrays::varbinview::VarBinViewArrayExt as _;
    use vortex::array::validity::Validity;

    if let Some(filter) = target.as_opt::<Filter>() {
        return fast_utf8_contains_count_from_filtered_array(filter, needle, negated);
    }
    if let Some(chunked) = target.as_opt::<Chunked>() {
        let mut selected = 0usize;
        for child in chunked.iter_chunks() {
            let Some(child_selected) = fast_utf8_contains_count_from_array(child, needle, negated)?
            else {
                return Ok(None);
            };
            selected = selected.checked_add(child_selected).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex chunked UTF-8 contains selected row count overflowed usize"
                        .to_string(),
                )
            })?;
        }
        return Ok(Some(selected));
    }
    if let Some(selected) = fast_utf8_contains_count_from_fsst_array(target, needle, negated)? {
        return Ok(Some(selected));
    }
    if let Some(selected) = fast_utf8_contains_count_from_dictionary_array(target, needle, negated)?
    {
        return Ok(Some(selected));
    }
    if !target.is_host() {
        return Ok(None);
    }
    let Some(utf8) = target.as_opt::<VarBinView>() else {
        return Ok(None);
    };
    let validity = utf8.varbinview_validity();
    let mut validity_ctx = vortex::array::LEGACY_SESSION.create_execution_ctx();
    let matcher = Utf8ContainsMatcher::new(needle, negated);
    let mut selected = 0usize;
    match &validity {
        Validity::NonNullable | Validity::AllValid => {
            for index in 0..utf8.len() {
                let bytes = utf8.bytes_at(index);
                let Some(matched) = matcher.matches_bytes(bytes.as_slice()) else {
                    return Ok(None);
                };
                if matched {
                    selected = selected.checked_add(1).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "local Vortex fast UTF-8 contains selected row count overflowed usize"
                                .to_string(),
                        )
                    })?;
                }
            }
        }
        Validity::AllInvalid => return Ok(Some(0)),
        Validity::Array(_) => {
            for index in 0..utf8.len() {
                if !validity
                    .execute_is_valid(index, &mut validity_ctx)
                    .map_err(vortex_error)?
                {
                    continue;
                }
                let bytes = utf8.bytes_at(index);
                let Some(matched) = matcher.matches_bytes(bytes.as_slice()) else {
                    return Ok(None);
                };
                if matched {
                    selected = selected.checked_add(1).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "local Vortex fast UTF-8 contains selected row count overflowed usize"
                                .to_string(),
                        )
                    })?;
                }
            }
        }
    }
    Ok(Some(selected))
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_contains_row_indices_from_chunk(
    chunk: &vortex::array::ArrayRef,
    columns: &[String],
    column_index: usize,
    needle: &str,
    negated: bool,
) -> Result<Option<Vec<usize>>> {
    let Some(target) = projected_array_from_chunk(chunk, columns, column_index) else {
        return Ok(None);
    };
    if !matches!(target.dtype(), vortex::array::dtype::DType::Utf8(_)) {
        return Ok(None);
    }
    fast_utf8_contains_row_indices_from_array(&target, needle, negated, 0)
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_contains_row_indices_from_array(
    target: &vortex::array::ArrayRef,
    needle: &str,
    negated: bool,
    base_offset: usize,
) -> Result<Option<Vec<usize>>> {
    use vortex::array::VortexSessionExecute as _;
    use vortex::array::arrays::Chunked;
    use vortex::array::arrays::Filter;
    use vortex::array::arrays::chunked::ChunkedArrayExt as _;
    use vortex::array::arrays::varbinview::VarBinView;
    use vortex::array::arrays::varbinview::VarBinViewArrayExt as _;
    use vortex::array::validity::Validity;

    if let Some(filter) = target.as_opt::<Filter>() {
        return fast_utf8_contains_row_indices_from_filtered_array(
            filter,
            needle,
            negated,
            base_offset,
        );
    }
    if let Some(chunked) = target.as_opt::<Chunked>() {
        let mut selected = Vec::new();
        let mut offset = base_offset;
        for child in chunked.iter_chunks() {
            let Some(child_indices) =
                fast_utf8_contains_row_indices_from_array(child, needle, negated, offset)?
            else {
                return Ok(None);
            };
            selected.extend(child_indices);
            offset = offset.checked_add(child.len()).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex chunked UTF-8 contains row offset overflowed usize".to_string(),
                )
            })?;
        }
        return Ok(Some(selected));
    }
    if let Some(indices) =
        fast_utf8_contains_row_indices_from_fsst_array(target, needle, negated, base_offset)?
    {
        return Ok(Some(indices));
    }
    if let Some(indices) =
        fast_utf8_contains_row_indices_from_dictionary_array(target, needle, negated)?
    {
        return add_row_index_offset(indices, base_offset).map(Some);
    }
    if !target.is_host() {
        return Ok(None);
    }
    let Some(utf8) = target.as_opt::<VarBinView>() else {
        return Ok(None);
    };
    let validity = utf8.varbinview_validity();
    let mut validity_ctx = vortex::array::LEGACY_SESSION.create_execution_ctx();
    let matcher = Utf8ContainsMatcher::new(needle, negated);
    let mut selected = Vec::new();
    match &validity {
        Validity::NonNullable | Validity::AllValid => {
            for index in 0..utf8.len() {
                let bytes = utf8.bytes_at(index);
                let Some(matched) = matcher.matches_bytes(bytes.as_slice()) else {
                    return Ok(None);
                };
                if matched {
                    selected.push(base_offset.checked_add(index).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "local Vortex UTF-8 contains row index overflowed usize".to_string(),
                        )
                    })?);
                }
            }
        }
        Validity::AllInvalid => return Ok(Some(selected)),
        Validity::Array(_) => {
            for index in 0..utf8.len() {
                if !validity
                    .execute_is_valid(index, &mut validity_ctx)
                    .map_err(vortex_error)?
                {
                    continue;
                }
                let bytes = utf8.bytes_at(index);
                let Some(matched) = matcher.matches_bytes(bytes.as_slice()) else {
                    return Ok(None);
                };
                if matched {
                    selected.push(base_offset.checked_add(index).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "local Vortex UTF-8 contains row index overflowed usize".to_string(),
                        )
                    })?);
                }
            }
        }
    }
    Ok(Some(selected))
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_contains_count_from_filtered_array(
    filter: vortex::array::ArrayView<'_, vortex::array::arrays::Filter>,
    needle: &str,
    negated: bool,
) -> Result<Option<usize>> {
    use vortex::array::arrays::filter::FilterArrayExt as _;

    let mask = filter.filter_mask();
    if let Some(selected) =
        fast_utf8_contains_count_from_masked_array(filter.child(), mask, needle, negated)?
    {
        return Ok(Some(selected));
    }
    let Some(child_indices) =
        fast_utf8_contains_row_indices_from_array(filter.child(), needle, negated, 0)?
    else {
        return Ok(None);
    };
    let mut selected = 0usize;
    for child_index in child_indices {
        if child_index >= mask.len() {
            return Ok(None);
        }
        if mask.value(child_index) {
            selected = selected.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex filtered UTF-8 contains selected row count overflowed usize"
                        .to_string(),
                )
            })?;
        }
    }
    Ok(Some(selected))
}

#[cfg(feature = "vortex-local-primitives")]
fn fast_utf8_contains_row_indices_from_filtered_array(
    filter: vortex::array::ArrayView<'_, vortex::array::arrays::Filter>,
    needle: &str,
    negated: bool,
    base_offset: usize,
) -> Result<Option<Vec<usize>>> {
    use vortex::array::arrays::filter::FilterArrayExt as _;

    let mask = filter.filter_mask();
    if let Some(selected) =
        fast_utf8_contains_row_indices_from_masked_array(filter.child(), mask, needle, negated)?
    {
        return add_row_index_offset(selected, base_offset).map(Some);
    }
    let Some(child_indices) =
        fast_utf8_contains_row_indices_from_array(filter.child(), needle, negated, 0)?
    else {
        return Ok(None);
    };
    let mut child_indices = child_indices.into_iter().peekable();
    let mut filtered_row_index = 0usize;
    let mut selected = Vec::new();
    for (source_row_index, mask_selected) in mask.iter().enumerate() {
        while child_indices
            .peek()
            .is_some_and(|child_index| *child_index < source_row_index)
        {
            child_indices.next();
        }
        let child_matched = child_indices
            .peek()
            .is_some_and(|child_index| *child_index == source_row_index);
        if child_matched && mask_selected {
            selected.push(base_offset.checked_add(filtered_row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex filtered UTF-8 contains row index overflowed usize".to_string(),
                )
            })?);
        }
        if child_matched {
            child_indices.next();
        }
        if mask_selected {
            filtered_row_index = filtered_row_index.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex filtered UTF-8 contains filtered row index overflowed usize"
                        .to_string(),
                )
            })?;
        }
    }
    if child_indices.next().is_some() {
        return Ok(None);
    }
    Ok(Some(selected))
}

