#[cfg(feature = "vortex-local-primitives")]
#[derive(Default)]
struct AggregateStringInterner {
    ids: rustc_hash::FxHashMap<std::sync::Arc<str>, u64>,
    values: Vec<std::sync::Arc<str>>,
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateStringInterner {
    fn reserve(&mut self, additional: usize, label: &str) -> Result<()> {
        reserve_hash_map_capacity(&mut self.ids, additional, label)?;
        self.values.try_reserve(additional).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex {label} value reservation failed: {error}; no fallback execution was attempted"
            ))
        })
    }

    fn intern(&mut self, value: &str) -> Result<u64> {
        if let Some(id) = self.ids.get(value) {
            return Ok(*id);
        }
        let id = usize_to_u64(self.values.len())?;
        let value: std::sync::Arc<str> = std::sync::Arc::from(value);
        self.values.push(std::sync::Arc::clone(&value));
        self.ids.insert(value, id);
        Ok(id)
    }

    fn intern_arc(&mut self, value: std::sync::Arc<str>) -> Result<u64> {
        if let Some(id) = self.ids.get(value.as_ref()) {
            return Ok(*id);
        }
        let id = usize_to_u64(self.values.len())?;
        self.values.push(std::sync::Arc::clone(&value));
        self.ids.insert(value, id);
        Ok(id)
    }

    fn id(&self, value: &str) -> Option<u64> {
        self.ids.get(value).copied()
    }

    fn value(&self, id: u64) -> Result<&str> {
        let index = usize::try_from(id).map_err(|_| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate interned string id exceeded usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        self.values.get(index).map(AsRef::as_ref).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate interned string id was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })
    }

    fn value_arc(&self, id: u64) -> Result<std::sync::Arc<str>> {
        let index = usize::try_from(id).map_err(|_| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate interned string id exceeded usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        self.values.get(index).cloned().ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate interned string id was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })
    }

    fn forget_id(&mut self, id: u64, label: &str) -> Result<()> {
        let value = self.value_arc(id)?;
        self.ids.remove(value.as_ref()).ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex {label} active string id was missing from the interner; no fallback execution was attempted"
            ))
        })?;
        Ok(())
    }

    fn len(&self) -> usize {
        self.values.len()
    }

    fn retained_bytes(&self) -> usize {
        self.values.iter().map(|value| value.len()).sum()
    }
}

