#[cfg(feature = "vortex-local-primitives")]
type NumericUtf8ExactDictionaryInputs<'a> = (&'a [u32], &'a [std::sync::Arc<str>]);

#[cfg(feature = "vortex-local-primitives")]
type SourceOrderNumericUtf8DirectInputs<'a> = (
    &'a AggregateDirectColumnAccessor,
    &'a [u32],
    &'a [std::sync::Arc<str>],
);

#[cfg(feature = "vortex-local-primitives")]
fn numeric_utf8_topk_chunk_compaction_admitted(
    numeric_accessor: &AggregateDirectColumnAccessor,
    utf8_accessor: &AggregateDirectColumnAccessor,
    dictionary_string_ids: &[u64],
) -> Result<bool> {
    const MIN_ROWS: usize = 16_384;
    const SAMPLE_ROWS: usize = 4096;
    let rows = numeric_accessor.len();
    if rows < MIN_ROWS || rows != utf8_accessor.len() {
        return Ok(false);
    }
    let sample_rows = SAMPLE_ROWS.min(rows);
    let mut sampled = rustc_hash::FxHashSet::<AggregateNumericUtf8InternedKey>::default();
    reserve_hash_set_capacity(
        &mut sampled,
        sample_rows,
        "numeric-UTF8 top-K chunk-compaction sample",
    )?;
    for sample_index in 0..sample_rows {
        let row_index = sample_index.checked_mul(rows).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex numeric-UTF8 top-K sample row index overflowed".to_string(),
            )
        })? / sample_rows;
        let numeric =
            aggregate_direct_integer_key_part(numeric_accessor, row_index, "numeric-UTF8")?;
        let utf8_id = aggregate_direct_utf8_dictionary_bound_id(
            utf8_accessor,
            dictionary_string_ids,
            row_index,
        )?;
        sampled.insert(AggregateNumericUtf8InternedKey::new(numeric, utf8_id));
    }
    Ok(sampled.len().saturating_mul(4) <= sample_rows.saturating_mul(3))
}

#[cfg(feature = "vortex-local-primitives")]
fn numeric_utf8_topk_chunk_counts(
    numeric_accessor: &AggregateDirectColumnAccessor,
    utf8_accessor: &AggregateDirectColumnAccessor,
    dictionary_string_ids: &[u64],
) -> Result<rustc_hash::FxHashMap<AggregateNumericUtf8InternedKey, u64>> {
    let rows = numeric_accessor.len();
    if rows != utf8_accessor.len() {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex numeric-UTF8 top-K chunk compaction saw inconsistent row counts; no fallback execution was attempted"
                .to_string(),
        ));
    }
    let mut counts = rustc_hash::FxHashMap::<AggregateNumericUtf8InternedKey, u64>::default();
    reserve_hash_map_capacity(
        &mut counts,
        rows.min(65_536),
        "numeric-UTF8 top-K chunk-compacted key counts",
    )?;
    for row_index in 0..rows {
        let numeric =
            aggregate_direct_integer_key_part(numeric_accessor, row_index, "numeric-UTF8")?;
        let utf8_id = aggregate_direct_utf8_dictionary_bound_id(
            utf8_accessor,
            dictionary_string_ids,
            row_index,
        )?;
        let key = AggregateNumericUtf8InternedKey::new(numeric, utf8_id);
        let count = counts.entry(key).or_insert(0);
        *count = count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex numeric-UTF8 top-K chunk-compacted count overflowed u64".to_string(),
            )
        })?;
    }
    Ok(counts)
}

#[cfg(feature = "vortex-local-primitives")]
fn source_order_numeric_utf8_direct_inputs(
    accessors: &[AggregateDirectColumnAccessor],
    roles: NumericUtf8GroupRoles,
) -> Result<Option<SourceOrderNumericUtf8DirectInputs<'_>>> {
    let numeric_accessor = accessors.get(roles.numeric_column).ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex source-order numeric-UTF8 aggregate numeric key column was missing; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    let utf8_accessor = accessors.get(roles.utf8_column).ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex source-order numeric-UTF8 aggregate UTF-8 key column was missing; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    let AggregateDirectColumnAccessor::Utf8Dictionary {
        row_ids,
        values,
        value_nulls,
        row_nulls,
        ..
    } = utf8_accessor
    else {
        return Ok(None);
    };
    if numeric_accessor.len() != row_ids.len() {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex source-order numeric-UTF8 aggregate key columns had inconsistent row counts; no fallback execution was attempted"
                .to_string(),
        ));
    }
    if !aggregate_utf8_dictionary_value_nulls_are_absent(
        value_nulls.as_deref(),
        row_nulls.as_deref(),
    ) {
        return Ok(None);
    }
    Ok(Some((numeric_accessor, row_ids, values)))
}

#[cfg(feature = "vortex-local-primitives")]
fn numeric_utf8_topk_exact_dictionary_inputs<'a>(
    numeric_accessor: &AggregateDirectColumnAccessor,
    utf8_accessor: &'a AggregateDirectColumnAccessor,
) -> Result<Option<NumericUtf8ExactDictionaryInputs<'a>>> {
    if numeric_accessor.len() != utf8_accessor.len() {
        return Ok(None);
    }
    let AggregateDirectColumnAccessor::Utf8Dictionary {
        row_ids,
        values,
        value_nulls,
        row_nulls,
        ..
    } = utf8_accessor
    else {
        return Ok(None);
    };
    if !aggregate_utf8_dictionary_value_nulls_are_absent(
        value_nulls.as_deref(),
        row_nulls.as_deref(),
    ) {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex numeric-UTF8 top-K heavy-hitter exact recount lost its non-null dictionary contract; no fallback execution was attempted"
                .to_string(),
        ));
    }
    Ok(Some((row_ids, values)))
}

#[cfg(feature = "vortex-local-primitives")]
fn numeric_utf8_candidate_parts_by_dictionary_code(
    values: &[std::sync::Arc<str>],
    string_interner: &AggregateStringInterner,
    candidates: &rustc_hash::FxHashSet<AggregateNumericUtf8InternedKey>,
) -> Vec<Option<rustc_hash::FxHashSet<(u64, bool)>>> {
    let mut code_by_id = rustc_hash::FxHashMap::<u64, usize>::default();
    for (code_index, value) in values.iter().enumerate() {
        if let Some(value_id) = string_interner.id(value.as_ref()) {
            code_by_id.insert(value_id, code_index);
        }
    }
    let mut candidate_numeric_by_code = (0..values.len()).map(|_| None).collect::<Vec<_>>();
    for candidate in candidates {
        let Some(&code_index) = code_by_id.get(&candidate.utf8_id) else {
            continue;
        };
        candidate_numeric_by_code[code_index]
            .get_or_insert_with(rustc_hash::FxHashSet::default)
            .insert((candidate.numeric_bits, candidate.numeric_signed));
    }
    candidate_numeric_by_code
}

#[cfg(feature = "vortex-local-primitives")]
fn numeric_utf8_topk_exact_chunk_counts(
    numeric_accessor: &AggregateDirectColumnAccessor,
    row_ids: &[u32],
    values: &[std::sync::Arc<str>],
    candidate_numeric_by_code: &[Option<rustc_hash::FxHashSet<(u64, bool)>>],
    string_interner: &AggregateStringInterner,
) -> Result<rustc_hash::FxHashMap<AggregateNumericUtf8InternedKey, u64>> {
    let mut chunk_counts = rustc_hash::FxHashMap::<AggregateNumericUtf8InternedKey, u64>::default();
    reserve_hash_map_capacity(
        &mut chunk_counts,
        candidate_numeric_by_code.len().min(numeric_accessor.len()),
        "numeric-UTF8 top-K chunk exact counts",
    )?;
    for row_index in 0..numeric_accessor.len() {
        let code_index = aggregate_utf8_dictionary_code_index(row_ids, row_index)?;
        let Some(candidate_numeric_parts) = candidate_numeric_by_code
            .get(code_index)
            .and_then(Option::as_ref)
        else {
            if code_index >= candidate_numeric_by_code.len() {
                return Err(ShardLoomError::InvalidOperation(
                    "local Vortex numeric-UTF8 top-K heavy-hitter dictionary value was missing; no fallback execution was attempted"
                        .to_string(),
                ));
            }
            continue;
        };
        let numeric =
            aggregate_direct_integer_key_part(numeric_accessor, row_index, "numeric-UTF8")?;
        if !candidate_numeric_parts.contains(&(numeric.bits, numeric.signed)) {
            continue;
        }
        let Some(utf8_id) = string_interner.id(values.get(code_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex numeric-UTF8 top-K heavy-hitter dictionary value was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?) else {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex numeric-UTF8 top-K heavy-hitter exact recount reached an uninterned dictionary value; no fallback execution was attempted"
                    .to_string(),
            ));
        };
        let count = chunk_counts
            .entry(AggregateNumericUtf8InternedKey::new(numeric, utf8_id))
            .or_insert(0);
        *count = count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex numeric-UTF8 top-K heavy-hitter exact count overflowed u64"
                    .to_string(),
            )
        })?;
    }
    Ok(chunk_counts)
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_numeric_utf8_topk_candidates(
    left: &NumericUtf8TopKCandidate,
    right: &NumericUtf8TopKCandidate,
    roles: NumericUtf8GroupRoles,
) -> std::cmp::Ordering {
    compare_numeric_utf8_key_to_topk_candidate(&left.key, left.count, right, roles)
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_numeric_utf8_key_to_topk_candidate(
    left_key: &AggregateNumericUtf8Key,
    left_count: u64,
    right: &NumericUtf8TopKCandidate,
    roles: NumericUtf8GroupRoles,
) -> std::cmp::Ordering {
    let count_order = left_count.cmp(&right.count).reverse();
    if count_order != std::cmp::Ordering::Equal {
        return count_order;
    }
    let numeric_order = || {
        compare_integer_key_bits(
            left_key.numeric_bits,
            left_key.numeric_signed,
            right.key.numeric_bits,
            right.key.numeric_signed,
        )
    };
    let utf8_order = || left_key.utf8.as_ref().cmp(right.key.utf8.as_ref());
    if roles.numeric_group < roles.utf8_group {
        numeric_order().then_with(utf8_order)
    } else {
        utf8_order().then_with(numeric_order)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_single_numeric_keys(
    left: AggregateSingleNumericKey,
    right: AggregateSingleNumericKey,
) -> std::cmp::Ordering {
    compare_integer_key_bits(left.bits, left.signed, right.bits, right.signed)
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_numeric_pair_key_part(
    left: AggregateNumericPairKey,
    right: AggregateNumericPairKey,
    first: bool,
) -> std::cmp::Ordering {
    let (left_bits, right_bits, signed_mask) = if first {
        (
            left.first_bits,
            right.first_bits,
            AggregateNumericPairKey::FIRST_SIGNED,
        )
    } else {
        (
            left.second_bits,
            right.second_bits,
            AggregateNumericPairKey::SECOND_SIGNED,
        )
    };
    let left_signed = left.key_kinds & signed_mask != 0;
    let right_signed = right.key_kinds & signed_mask != 0;
    compare_integer_key_bits(left_bits, left_signed, right_bits, right_signed)
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_integer_key_bits(
    left_bits: u64,
    left_signed: bool,
    right_bits: u64,
    right_signed: bool,
) -> std::cmp::Ordering {
    match (left_signed, right_signed) {
        (true, true) => {
            signed_integer_from_bits(left_bits).cmp(&signed_integer_from_bits(right_bits))
        }
        (false, false) => left_bits.cmp(&right_bits),
        (true, false) => std::cmp::Ordering::Less,
        (false, true) => std::cmp::Ordering::Greater,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn signed_integer_from_bits(bits: u64) -> i64 {
    i64::from_ne_bytes(bits.to_ne_bytes())
}

#[cfg(feature = "vortex-local-primitives")]
fn integer_key_json_value(bits: u64, signed: bool) -> serde_json::Value {
    if signed {
        serde_json::Value::Number(signed_integer_from_bits(bits).into())
    } else {
        serde_json::Value::Number(bits.into())
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn integer_key_distinct_value(bits: u64, signed: bool) -> AggregateDistinctValue {
    if signed {
        AggregateDistinctValue::Int64(signed_integer_from_bits(bits))
    } else {
        AggregateDistinctValue::UInt64(bits)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_distinct_integer_key_part(
    value: &AggregateDistinctValue,
) -> Option<AggregateIntegerKeyPart> {
    match value {
        AggregateDistinctValue::Int64(value) => Some(AggregateIntegerKeyPart {
            bits: value.cast_unsigned(),
            signed: true,
        }),
        AggregateDistinctValue::UInt64(value) => Some(AggregateIntegerKeyPart {
            bits: *value,
            signed: false,
        }),
        AggregateDistinctValue::Null
        | AggregateDistinctValue::Boolean(_)
        | AggregateDistinctValue::Float64Bits(_)
        | AggregateDistinctValue::Utf8(_)
        | AggregateDistinctValue::Utf8Interned(_) => None,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_distinct_utf8_interned_id(
    value: &AggregateDistinctValue,
    interner: &AggregateStringInterner,
) -> Option<u64> {
    match value {
        AggregateDistinctValue::Utf8Interned(id) => Some(*id),
        AggregateDistinctValue::Utf8(value) => interner.id(value.as_ref()),
        AggregateDistinctValue::Null
        | AggregateDistinctValue::Boolean(_)
        | AggregateDistinctValue::Int64(_)
        | AggregateDistinctValue::UInt64(_)
        | AggregateDistinctValue::Float64Bits(_) => None,
    }
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateGroupKey {
    fn from_indices(values: &[StatValue], indices: &[usize]) -> Self {
        Self::from_values(
            indices
                .iter()
                .filter_map(|index| values.get(*index))
                .map(AggregateDistinctValue::from)
                .collect(),
        )
    }

    fn from_values(values: Vec<AggregateDistinctValue>) -> Self {
        let mut values = values.into_iter();
        match (values.next(), values.next(), values.next(), values.next()) {
            (None, None, None, None) => Self::Empty,
            (Some(first), None, None, None) => Self::Single(first),
            (Some(first), Some(second), None, None) => Self::Pair(first, second),
            (Some(first), Some(second), Some(third), None) => Self::Triple(first, second, third),
            (first, second, third, fourth) => {
                let mut out = Vec::with_capacity(4 + values.size_hint().0);
                if let Some(value) = first {
                    out.push(value);
                }
                if let Some(value) = second {
                    out.push(value);
                }
                if let Some(value) = third {
                    out.push(value);
                }
                if let Some(value) = fourth {
                    out.push(value);
                }
                out.extend(values);
                Self::Many(out)
            }
        }
    }

    fn single(value: AggregateDistinctValue) -> Self {
        Self::Single(value)
    }

    fn get(&self, index: usize) -> Option<&AggregateDistinctValue> {
        match (self, index) {
            (Self::Single(first) | Self::Pair(first, _) | Self::Triple(first, _, _), 0) => {
                Some(first)
            }
            (Self::Pair(_, second) | Self::Triple(_, second, _), 1) => Some(second),
            (Self::Triple(_, _, third), 2) => Some(third),
            (Self::Many(values), index) => values.get(index),
            _ => None,
        }
    }

    fn len(&self) -> usize {
        match self {
            Self::Empty => 0,
            Self::Single(_) => 1,
            Self::Pair(_, _) => 2,
            Self::Triple(_, _, _) => 3,
            Self::Many(values) => values.len(),
        }
    }

    fn estimated_storage_bytes(&self) -> usize {
        match self {
            Self::Empty => 0,
            Self::Single(first) => first.estimated_storage_bytes(),
            Self::Pair(first, second) => first
                .estimated_storage_bytes()
                .saturating_add(second.estimated_storage_bytes()),
            Self::Triple(first, second, third) => first
                .estimated_storage_bytes()
                .saturating_add(second.estimated_storage_bytes())
                .saturating_add(third.estimated_storage_bytes()),
            Self::Many(values) => values
                .iter()
                .map(AggregateDistinctValue::estimated_storage_bytes)
                .sum(),
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_aggregate_group_keys(
    left: &AggregateGroupKey,
    right: &AggregateGroupKey,
    interner: &AggregateStringInterner,
) -> std::cmp::Ordering {
    for index in 0..left.len().max(right.len()) {
        match (left.get(index), right.get(index)) {
            (Some(left_value), Some(right_value)) => {
                let ordering = compare_aggregate_distinct_values(left_value, right_value, interner);
                if ordering != std::cmp::Ordering::Equal {
                    return ordering;
                }
            }
            (Some(_), None) => return std::cmp::Ordering::Greater,
            (None, Some(_)) => return std::cmp::Ordering::Less,
            (None, None) => return std::cmp::Ordering::Equal,
        }
    }
    std::cmp::Ordering::Equal
}

#[cfg(feature = "vortex-local-primitives")]
fn compare_aggregate_distinct_values(
    left: &AggregateDistinctValue,
    right: &AggregateDistinctValue,
    interner: &AggregateStringInterner,
) -> std::cmp::Ordering {
    let left_rank = aggregate_distinct_value_rank(left);
    let right_rank = aggregate_distinct_value_rank(right);
    if left_rank != right_rank {
        return left_rank.cmp(&right_rank);
    }
    match (left, right) {
        (AggregateDistinctValue::Boolean(left), AggregateDistinctValue::Boolean(right)) => {
            left.cmp(right)
        }
        (AggregateDistinctValue::Int64(left), AggregateDistinctValue::Int64(right)) => {
            left.cmp(right)
        }
        (AggregateDistinctValue::UInt64(left), AggregateDistinctValue::UInt64(right)) => {
            left.cmp(right)
        }
        (AggregateDistinctValue::Float64Bits(left), AggregateDistinctValue::Float64Bits(right)) => {
            f64::from_bits(*left).total_cmp(&f64::from_bits(*right))
        }
        (AggregateDistinctValue::Utf8(left), AggregateDistinctValue::Utf8(right)) => {
            left.as_ref().cmp(right.as_ref())
        }
        (AggregateDistinctValue::Utf8(left), AggregateDistinctValue::Utf8Interned(right)) => left
            .as_ref()
            .cmp(interner.value(*right).unwrap_or_default()),
        (AggregateDistinctValue::Utf8Interned(left), AggregateDistinctValue::Utf8(right)) => {
            interner
                .value(*left)
                .unwrap_or_default()
                .cmp(right.as_ref())
        }
        (
            AggregateDistinctValue::Utf8Interned(left),
            AggregateDistinctValue::Utf8Interned(right),
        ) => interner
            .value(*left)
            .unwrap_or_default()
            .cmp(interner.value(*right).unwrap_or_default()),
        _ => std::cmp::Ordering::Equal,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_distinct_value_rank(value: &AggregateDistinctValue) -> u8 {
    match value {
        AggregateDistinctValue::Null => 0,
        AggregateDistinctValue::Boolean(_) => 1,
        AggregateDistinctValue::Int64(_) => 2,
        AggregateDistinctValue::UInt64(_) => 3,
        AggregateDistinctValue::Float64Bits(_) => 4,
        AggregateDistinctValue::Utf8(_) | AggregateDistinctValue::Utf8Interned(_) => 5,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn single_group_fast_key(
    group_column: &AggregateGroupRuntimeColumn,
    value: &StatValue,
) -> Result<Option<AggregateGroupKey>> {
    match &group_column.transform {
        AggregateValueTransform::Identity => Ok(Some(AggregateGroupKey::single(
            AggregateDistinctValue::from(value),
        ))),
        AggregateValueTransform::Length => match value {
            StatValue::Utf8(value) => Ok(Some(AggregateGroupKey::single(
                AggregateDistinctValue::UInt64(usize_to_u64(value.len())?),
            ))),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate length fast path requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::UrlDomain => match value {
            StatValue::Utf8(value) => Ok(Some(AggregateGroupKey::single(
                AggregateDistinctValue::Utf8(std::sync::Arc::<str>::from(
                    aggregate_url_domain_str(value),
                )),
            ))),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate URL-domain fast path requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::ConstantInt(_)
        | AggregateValueTransform::AddOffset(_)
        | AggregateValueTransform::ExtractMinute
        | AggregateValueTransform::DateTruncMinute
        | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => Ok(None),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn single_group_fast_value(
    group_column: &AggregateGroupRuntimeColumn,
    value: &StatValue,
) -> Result<StatValue> {
    match &group_column.transform {
        AggregateValueTransform::Identity => Ok(value.clone()),
        AggregateValueTransform::Length => match value {
            StatValue::Utf8(value) => Ok(StatValue::UInt64(usize_to_u64(value.len())?)),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate length fast path requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::UrlDomain => match value {
            StatValue::Utf8(value) => {
                Ok(StatValue::Utf8(aggregate_url_domain_str(value).to_string()))
            }
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate URL-domain fast path requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::ConstantInt(_)
        | AggregateValueTransform::AddOffset(_)
        | AggregateValueTransform::ExtractMinute
        | AggregateValueTransform::DateTruncMinute
        | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
            group_column.transform.apply(value)
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
enum AggregateDirectColumnAccessor {
    Boolean(Vec<bool>),
    NullableBoolean {
        values: Vec<bool>,
        row_nulls: Vec<bool>,
    },
    UInt64(Vec<u64>),
    NullableUInt64 {
        values: Vec<u64>,
        row_nulls: Vec<bool>,
    },
    Int64(Vec<i64>),
    NullableInt64 {
        values: Vec<i64>,
        row_nulls: Vec<bool>,
    },
    Float64(Vec<f64>),
    NullableFloat64 {
        values: Vec<f64>,
        row_nulls: Vec<bool>,
    },
    Utf8Dictionary {
        row_ids: Vec<u32>,
        values: Vec<std::sync::Arc<str>>,
        value_nulls: Option<Vec<bool>>,
        row_nulls: Option<Vec<bool>>,
        source: AggregateUtf8DictionarySource,
    },
    Materialized {
        values: Vec<StatValue>,
        blocker: &'static str,
    },
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone, Copy)]
enum AggregateUtf8DictionarySource {
    VortexDictArray,
    HostUtf8ChunkDictionary,
    DecodedUtf8ChunkDictionary,
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateUtf8DictionarySource {
    const fn evidence_kind(self) -> &'static str {
        match self {
            Self::VortexDictArray => "vortex_utf8_dictionary",
            Self::HostUtf8ChunkDictionary => "chunk_utf8_dictionary",
            Self::DecodedUtf8ChunkDictionary => "decoded_utf8_chunk_dictionary",
        }
    }

    const fn evidence_family(self) -> AggregateDirectColumnAccessorEvidenceFamily {
        match self {
            Self::VortexDictArray => AggregateDirectColumnAccessorEvidenceFamily::VortexDictionary,
            Self::HostUtf8ChunkDictionary | Self::DecodedUtf8ChunkDictionary => {
                AggregateDirectColumnAccessorEvidenceFamily::ChunkDictionary
            }
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone, Copy)]
enum AggregateDirectColumnAccessorEvidenceFamily {
    Primitive,
    VortexDictionary,
    ChunkDictionary,
    Materialized,
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_accessor_set_summary(values: &std::collections::BTreeSet<String>) -> String {
    if values.is_empty() {
        "none".to_string()
    } else {
        values.iter().cloned().collect::<Vec<_>>().join(",")
    }
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone, Copy, Debug, Eq, Hash, PartialEq)]
enum AggregateMaterializedStringPartialKey<'a> {
    Null,
    UInt64(u64),
    Utf8(&'a str),
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone, Copy, Debug, Eq, Hash, PartialEq)]
enum DictionaryGroupCodeKey {
    Null,
    Code(u32),
}

#[cfg(feature = "vortex-local-primitives")]
fn dictionary_group_code_key_for_row(
    row_ids: &[u32],
    value_count: usize,
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    row_index: usize,
) -> Result<DictionaryGroupCodeKey> {
    if aggregate_utf8_dictionary_row_has_null(
        row_ids,
        value_count,
        value_nulls,
        row_nulls,
        row_index,
    )? {
        return Ok(DictionaryGroupCodeKey::Null);
    }
    row_ids
        .get(row_index)
        .copied()
        .map(DictionaryGroupCodeKey::Code)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex dictionary-group aggregate row index was out of bounds; no fallback execution was attempted"
                    .to_string(),
            )
        })
}

#[cfg(feature = "vortex-local-primitives")]
fn dictionary_group_code_key_to_aggregate_group_key(
    code_key: DictionaryGroupCodeKey,
    values: &[std::sync::Arc<str>],
    string_interner: &mut AggregateStringInterner,
) -> Result<AggregateGroupKey> {
    match code_key {
        DictionaryGroupCodeKey::Null => Ok(AggregateGroupKey::single(AggregateDistinctValue::Null)),
        DictionaryGroupCodeKey::Code(code) => {
            let value_index = usize::try_from(code).map_err(|error| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex dictionary-group aggregate code overflowed usize: {error}; no fallback execution was attempted"
                ))
            })?;
            let value = values.get(value_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex dictionary-group aggregate code referenced a missing dictionary value; no fallback execution was attempted"
                        .to_string(),
                )
            })?;
            Ok(AggregateGroupKey::single(
                AggregateDistinctValue::Utf8Interned(
                    string_interner.intern_arc(std::sync::Arc::clone(value))?,
                ),
            ))
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateMaterializedStringPartialKey<'_> {
    fn to_group_key(self, interner: &mut AggregateStringInterner) -> Result<AggregateGroupKey> {
        match self {
            Self::Null => Ok(AggregateGroupKey::single(AggregateDistinctValue::Null)),
            Self::UInt64(value) => Ok(AggregateGroupKey::single(AggregateDistinctValue::UInt64(
                value,
            ))),
            Self::Utf8(value) => Ok(AggregateGroupKey::single(
                AggregateDistinctValue::Utf8Interned(interner.intern(value)?),
            )),
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_materialized_string_partial_key(
    value: &StatValue,
    transform: AggregateValueTransform,
) -> Result<AggregateMaterializedStringPartialKey<'_>> {
    match transform {
        AggregateValueTransform::Identity => match value {
            StatValue::Null => Ok(AggregateMaterializedStringPartialKey::Null),
            StatValue::Utf8(value) => Ok(AggregateMaterializedStringPartialKey::Utf8(value)),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate materialized string-partial identity key requires UTF-8 or null input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::Length => match value {
            StatValue::Utf8(value) => Ok(AggregateMaterializedStringPartialKey::UInt64(
                usize_to_u64(value.len())?,
            )),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate materialized string-partial length key requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::UrlDomain => match value {
            StatValue::Utf8(value) => Ok(AggregateMaterializedStringPartialKey::Utf8(
                aggregate_url_domain_str(value),
            )),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex grouped aggregate materialized string-partial URL-domain key requires UTF-8 input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        },
        AggregateValueTransform::ConstantInt(_)
        | AggregateValueTransform::AddOffset(_)
        | AggregateValueTransform::ExtractMinute
        | AggregateValueTransform::DateTruncMinute
        | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
            Err(ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate materialized string-partial key transform is not admitted; no fallback execution was attempted"
                    .to_string(),
            ))
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateDirectColumnAccessor {
    fn materialized(values: Vec<StatValue>, blocker: &'static str) -> Self {
        Self::Materialized { values, blocker }
    }

    fn len(&self) -> usize {
        match self {
            Self::Boolean(values) | Self::NullableBoolean { values, .. } => values.len(),
            Self::UInt64(values) | Self::NullableUInt64 { values, .. } => values.len(),
            Self::Int64(values) | Self::NullableInt64 { values, .. } => values.len(),
            Self::Float64(values) | Self::NullableFloat64 { values, .. } => values.len(),
            Self::Utf8Dictionary { row_ids, .. } => row_ids.len(),
            Self::Materialized { values, .. } => values.len(),
        }
    }

    fn u64_values(&self) -> Option<&[u64]> {
        match self {
            Self::UInt64(values) => Some(values.as_slice()),
            _ => None,
        }
    }

    fn i64_values(&self) -> Option<&[i64]> {
        match self {
            Self::Int64(values) => Some(values.as_slice()),
            _ => None,
        }
    }

    fn f64_values(&self) -> Option<&[f64]> {
        match self {
            Self::Float64(values) => Some(values.as_slice()),
            _ => None,
        }
    }

    fn is_direct_integer(&self) -> bool {
        self.u64_values().is_some() || self.i64_values().is_some()
    }

    fn evidence_kind(&self) -> &'static str {
        match self {
            Self::Boolean(_) => "direct_bool",
            Self::NullableBoolean { .. } => "direct_bool_nullable",
            Self::UInt64(_) => "direct_u64",
            Self::NullableUInt64 { .. } => "direct_u64_nullable",
            Self::Int64(_) => "direct_i64",
            Self::NullableInt64 { .. } => "direct_i64_nullable",
            Self::Float64(_) => "direct_f64",
            Self::NullableFloat64 { .. } => "direct_f64_nullable",
            Self::Utf8Dictionary { source, .. } => source.evidence_kind(),
            Self::Materialized { .. } => "materialized_stat_values",
        }
    }

    const fn evidence_family(&self) -> AggregateDirectColumnAccessorEvidenceFamily {
        match self {
            Self::Boolean(_)
            | Self::NullableBoolean { .. }
            | Self::UInt64(_)
            | Self::NullableUInt64 { .. }
            | Self::Int64(_)
            | Self::NullableInt64 { .. }
            | Self::Float64(_)
            | Self::NullableFloat64 { .. } => {
                AggregateDirectColumnAccessorEvidenceFamily::Primitive
            }
            Self::Utf8Dictionary { source, .. } => source.evidence_family(),
            Self::Materialized { .. } => AggregateDirectColumnAccessorEvidenceFamily::Materialized,
        }
    }

    const fn materialization_blocker(&self) -> Option<&'static str> {
        match self {
            Self::Materialized { blocker, .. } => Some(*blocker),
            Self::Boolean(_)
            | Self::NullableBoolean { .. }
            | Self::UInt64(_)
            | Self::NullableUInt64 { .. }
            | Self::Int64(_)
            | Self::NullableInt64 { .. }
            | Self::Float64(_)
            | Self::NullableFloat64 { .. }
            | Self::Utf8Dictionary { .. } => None,
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_column_accessors_from_chunk(
    chunk: &vortex::array::ArrayRef,
    declared_columns: &[String],
) -> Result<Vec<AggregateDirectColumnAccessor>> {
    let mut out = Vec::with_capacity(declared_columns.len());
    if chunk.dtype().is_struct() {
        let children = chunk
            .named_children()
            .into_iter()
            .collect::<std::collections::BTreeMap<_, _>>();
        for column in declared_columns {
            let Some(array) = children.get(column.as_str()) else {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "local Vortex aggregate direct column '{column}' was not present in scanned chunk; no fallback execution was attempted"
                )));
            };
            out.push(aggregate_direct_column_accessor(column, array)?);
        }
    } else {
        let column = declared_columns.first().map_or("value", String::as_str);
        out.push(aggregate_direct_column_accessor(column, chunk)?);
    }
    Ok(out)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_integer_key_part(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
    label: &str,
) -> Result<AggregateIntegerKeyPart> {
    if let Some(values) = accessor.u64_values() {
        return values
            .get(row_index)
            .copied()
            .map(|bits| AggregateIntegerKeyPart {
                bits,
                signed: false,
            })
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex numeric-pair aggregate {label} key row index was out of bounds; no fallback execution was attempted"
                ))
            });
    }
    if let Some(values) = accessor.i64_values() {
        return values
            .get(row_index)
            .copied()
            .map(|value| AggregateIntegerKeyPart {
                bits: value.cast_unsigned(),
                signed: true,
            })
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex numeric-pair aggregate {label} key row index was out of bounds; no fallback execution was attempted"
                ))
            });
    }
    match accessor {
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            let value = values.get(row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex numeric-pair aggregate {label} key row index was out of bounds; no fallback execution was attempted"
                ))
            })?;
            match value {
                StatValue::UInt64(value) => Ok(AggregateIntegerKeyPart {
                    bits: *value,
                    signed: false,
                }),
                StatValue::Int64(value) => Ok(AggregateIntegerKeyPart {
                    bits: value.cast_unsigned(),
                    signed: true,
                }),
                other => Err(ShardLoomError::InvalidOperation(format!(
                    "local Vortex numeric-pair aggregate {label} key requires integer input, got {}; no fallback execution was attempted",
                    other.dtype().as_str()
                ))),
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. }
        | AggregateDirectColumnAccessor::Utf8Dictionary { .. } => {
            Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex numeric-pair aggregate {label} key requires integer input; no fallback execution was attempted"
            )))
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_single_numeric_key_accessor_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    aggregate_numeric_pair_key_accessor_admitted(accessor, row_indices)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_numeric_pair_key_accessor_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    if accessor.is_direct_integer() {
        return true;
    }
    match accessor {
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            if let Some(row_indices) = row_indices {
                row_indices.iter().all(|row_index| {
                    values.get(*row_index).is_some_and(|value| {
                        matches!(value, StatValue::UInt64(_) | StatValue::Int64(_))
                    })
                })
            } else {
                values
                    .iter()
                    .all(|value| matches!(value, StatValue::UInt64(_) | StatValue::Int64(_)))
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. }
        | AggregateDirectColumnAccessor::Utf8Dictionary { .. } => false,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_minute_key_accessor_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    if accessor.is_direct_integer() {
        return true;
    }
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => {
            let admits_row = |row_index: usize| {
                aggregate_utf8_dictionary_value(
                    row_ids,
                    values,
                    value_nulls.as_deref(),
                    row_nulls.as_deref(),
                    row_index,
                )
                .ok()
                .and_then(parse_timestamp_minute)
                .is_some()
            };
            if let Some(row_indices) = row_indices {
                row_indices.iter().copied().all(admits_row)
            } else {
                (0..row_ids.len()).all(admits_row)
            }
        }
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            let admits_value = |value: &StatValue| match value {
                StatValue::UInt64(_) | StatValue::Int64(_) => true,
                StatValue::Utf8(value) => parse_timestamp_minute(value).is_some(),
                _ => false,
            };
            if let Some(row_indices) = row_indices {
                row_indices
                    .iter()
                    .all(|row_index| values.get(*row_index).is_some_and(admits_value))
            } else {
                values.iter().all(admits_value)
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => false,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_prepared_minute_key_accessor_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    let admits_value = |value: &StatValue| match value {
        StatValue::UInt64(value) => *value < 60,
        StatValue::Int64(value) => (0..60).contains(value),
        _ => false,
    };
    if let Some(values) = accessor.u64_values() {
        return row_indices.map_or_else(
            || values.iter().all(|value| *value < 60),
            |row_indices| {
                row_indices
                    .iter()
                    .all(|row_index| values.get(*row_index).is_some_and(|value| *value < 60))
            },
        );
    }
    if let Some(values) = accessor.i64_values() {
        return row_indices.map_or_else(
            || values.iter().all(|value| (0..60).contains(value)),
            |row_indices| {
                row_indices.iter().all(|row_index| {
                    values
                        .get(*row_index)
                        .is_some_and(|value| (0..60).contains(value))
                })
            },
        );
    }
    match accessor {
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            if let Some(row_indices) = row_indices {
                row_indices
                    .iter()
                    .all(|row_index| values.get(*row_index).is_some_and(admits_value))
            } else {
                values.iter().all(admits_value)
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. }
        | AggregateDirectColumnAccessor::Utf8Dictionary { .. } => false,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_string_key_accessor_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => aggregate_utf8_dictionary_rows_are_non_null(
            row_ids,
            values.len(),
            value_nulls.as_deref(),
            row_nulls.as_deref(),
            row_indices,
        ),
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            if let Some(row_indices) = row_indices {
                row_indices.iter().all(|row_index| {
                    values
                        .get(*row_index)
                        .is_some_and(|value| matches!(value, StatValue::Utf8(_)))
                })
            } else {
                values
                    .iter()
                    .all(|value| matches!(value, StatValue::Utf8(_)))
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => false,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_non_null_row_count(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> Result<u64> {
    match accessor {
        AggregateDirectColumnAccessor::Boolean(values) => {
            aggregate_direct_row_count_for_len(values.len(), row_indices)
        }
        AggregateDirectColumnAccessor::NullableBoolean { values, row_nulls } => {
            aggregate_direct_non_null_row_count_for_nulls(values.len(), row_nulls, row_indices)
        }
        AggregateDirectColumnAccessor::UInt64(values) => {
            aggregate_direct_row_count_for_len(values.len(), row_indices)
        }
        AggregateDirectColumnAccessor::NullableUInt64 { values, row_nulls } => {
            aggregate_direct_non_null_row_count_for_nulls(values.len(), row_nulls, row_indices)
        }
        AggregateDirectColumnAccessor::Int64(values) => {
            aggregate_direct_row_count_for_len(values.len(), row_indices)
        }
        AggregateDirectColumnAccessor::NullableInt64 { values, row_nulls } => {
            aggregate_direct_non_null_row_count_for_nulls(values.len(), row_nulls, row_indices)
        }
        AggregateDirectColumnAccessor::Float64(values) => {
            aggregate_direct_row_count_for_len(values.len(), row_indices)
        }
        AggregateDirectColumnAccessor::NullableFloat64 { values, row_nulls } => {
            aggregate_direct_non_null_row_count_for_nulls(values.len(), row_nulls, row_indices)
        }
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => {
            aggregate_utf8_dictionary_value_nulls_match_len(
                values.len(),
                value_nulls.as_deref(),
                row_ids.len(),
                row_nulls.as_deref(),
            )?;
            if aggregate_utf8_dictionary_value_nulls_are_absent(
                value_nulls.as_deref(),
                row_nulls.as_deref(),
            ) {
                return aggregate_direct_row_count_for_len(row_ids.len(), row_indices);
            }
            let mut count = 0_u64;
            let mut update = |row_index| -> Result<()> {
                if !aggregate_utf8_dictionary_row_has_null(
                    row_ids,
                    values.len(),
                    value_nulls.as_deref(),
                    row_nulls.as_deref(),
                    row_index,
                )? {
                    count = count.checked_add(1).ok_or_else(|| {
                        ShardLoomError::InvalidOperation(
                            "local Vortex aggregate direct dictionary non-null count overflowed u64"
                                .to_string(),
                        )
                    })?;
                }
                Ok(())
            };
            if let Some(row_indices) = row_indices {
                for &row_index in row_indices {
                    update(row_index)?;
                }
            } else {
                for row_index in 0..row_ids.len() {
                    update(row_index)?;
                }
            }
            Ok(count)
        }
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            if let Some(row_indices) = row_indices {
                row_indices.iter().try_fold(0_u64, |count, row_index| {
                    let is_non_null = values
                        .get(*row_index)
                        .is_some_and(|value| !matches!(value, StatValue::Null));
                    if is_non_null {
                        count.checked_add(1).ok_or_else(|| {
                            ShardLoomError::InvalidOperation(
                                "local Vortex aggregate direct non-null count overflowed u64"
                                    .to_string(),
                            )
                        })
                    } else {
                        Ok(count)
                    }
                })
            } else {
                usize_to_u64(
                    values
                        .iter()
                        .filter(|value| !matches!(value, StatValue::Null))
                        .count(),
                )
            }
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_utf8_rows_admitted(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
) -> bool {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary { .. } => true,
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            if let Some(row_indices) = row_indices {
                row_indices.iter().all(|row_index| {
                    values
                        .get(*row_index)
                        .is_some_and(|value| matches!(value, StatValue::Utf8(_) | StatValue::Null))
                })
            } else {
                values
                    .iter()
                    .all(|value| matches!(value, StatValue::Utf8(_) | StatValue::Null))
            }
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => false,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_materialized_numeric_rows_admitted(
    values: &[StatValue],
    row_indices: Option<&[usize]>,
) -> bool {
    let admits = |value: &StatValue| {
        matches!(
            value,
            StatValue::UInt64(_) | StatValue::Int64(_) | StatValue::Float64(_) | StatValue::Null
        )
    };
    if let Some(row_indices) = row_indices {
        row_indices
            .iter()
            .all(|row_index| values.get(*row_index).is_some_and(admits))
    } else {
        values.iter().all(admits)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_materialized_comparable_rows_admitted(
    values: &[StatValue],
    row_indices: Option<&[usize]>,
) -> bool {
    let first_rank = if let Some(row_indices) = row_indices {
        row_indices
            .iter()
            .filter_map(|row_index| values.get(*row_index))
            .find_map(aggregate_comparable_rank)
    } else {
        values.iter().find_map(aggregate_comparable_rank)
    };
    let Some(first_rank) = first_rank else {
        return true;
    };
    let admits = |value: &StatValue| {
        matches!(value, StatValue::Null) || aggregate_comparable_rank(value) == Some(first_rank)
    };
    if let Some(row_indices) = row_indices {
        row_indices
            .iter()
            .all(|row_index| values.get(*row_index).is_some_and(admits))
    } else {
        values.iter().all(admits)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_comparable_rank(value: &StatValue) -> Option<u8> {
    match value {
        StatValue::Null => None,
        StatValue::Boolean(_) => Some(0),
        StatValue::Int64(_) | StatValue::UInt64(_) | StatValue::Float64(_) => Some(1),
        StatValue::Utf8(_) => Some(2),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_row_count_for_len(len: usize, row_indices: Option<&[usize]>) -> Result<u64> {
    if let Some(row_indices) = row_indices {
        if row_indices.iter().any(|row_index| *row_index >= len) {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex aggregate direct row index exceeded accessor length; no fallback execution was attempted"
                    .to_string(),
            ));
        }
        usize_to_u64(row_indices.len())
    } else {
        usize_to_u64(len)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_non_null_row_count_for_nulls(
    len: usize,
    row_nulls: &[bool],
    row_indices: Option<&[usize]>,
) -> Result<u64> {
    if row_nulls.len() != len {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct nullable primitive null mask length did not match values; no fallback execution was attempted"
                .to_string(),
        ));
    }
    let mut count = 0_u64;
    let mut update = |row_index: usize| -> Result<()> {
        if row_index >= len {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex aggregate direct nullable primitive row index exceeded accessor length; no fallback execution was attempted"
                    .to_string(),
            ));
        }
        if !row_nulls[row_index] {
            count = count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate direct nullable primitive non-null count overflowed u64"
                        .to_string(),
                )
            })?;
        }
        Ok(())
    };
    if let Some(row_indices) = row_indices {
        for &row_index in row_indices {
            update(row_index)?;
        }
    } else {
        for row_index in 0..len {
            update(row_index)?;
        }
    }
    Ok(count)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_nullable_primitive_value<T: Copy>(
    values: &[T],
    row_nulls: &[bool],
    row_index: usize,
    label: &str,
) -> Result<Option<T>> {
    if row_nulls.len() != values.len() {
        return Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex aggregate direct nullable primitive {label} null mask length did not match values; no fallback execution was attempted"
        )));
    }
    let value = values.get(row_index).copied().ok_or_else(|| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex aggregate direct nullable primitive {label} row index exceeded accessor length; no fallback execution was attempted"
        ))
    })?;
    Ok((!row_nulls[row_index]).then_some(value))
}

#[cfg(feature = "vortex-local-primitives")]
fn reserve_hash_map_capacity<K, V, S>(
    map: &mut std::collections::HashMap<K, V, S>,
    additional: usize,
    label: &str,
) -> Result<()>
where
    K: Eq + std::hash::Hash,
    S: std::hash::BuildHasher,
{
    if additional == 0 {
        return Ok(());
    }
    map.try_reserve(additional).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex {label} state reservation failed: {error}; no fallback execution was attempted"
        ))
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn reserve_hash_set_capacity<T, S>(
    set: &mut std::collections::HashSet<T, S>,
    additional: usize,
    label: &str,
) -> Result<()>
where
    T: Eq + std::hash::Hash,
    S: std::hash::BuildHasher,
{
    if additional == 0 {
        return Ok(());
    }
    set.try_reserve(additional).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex {label} state reservation failed: {error}; no fallback execution was attempted"
        ))
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_count_distinct_update(
    accessor: &AggregateDirectColumnAccessor,
    row_indices: Option<&[usize]>,
    distinct_values: &mut AggregateDistinctSet,
) -> Result<AggregateDirectCountDistinctUpdate> {
    match accessor {
        AggregateDirectColumnAccessor::Boolean(values) => {
            aggregate_direct_count_distinct_update_bool_report(
                values,
                None,
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::NullableBoolean { values, row_nulls } => {
            aggregate_direct_count_distinct_update_bool_report(
                values,
                Some(row_nulls),
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::UInt64(values) => {
            aggregate_direct_count_distinct_update_u64_report(
                values,
                None,
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::NullableUInt64 { values, row_nulls } => {
            aggregate_direct_count_distinct_update_u64_report(
                values,
                Some(row_nulls),
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::Int64(values) => {
            aggregate_direct_count_distinct_update_i64_report(
                values,
                None,
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::NullableInt64 { values, row_nulls } => {
            aggregate_direct_count_distinct_update_i64_report(
                values,
                Some(row_nulls),
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::Float64(values) => {
            aggregate_direct_count_distinct_update_f64_report(
                values,
                None,
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::NullableFloat64 { values, row_nulls } => {
            aggregate_direct_count_distinct_update_f64_report(
                values,
                Some(row_nulls),
                row_indices,
                distinct_values,
            )
        }
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => Ok(AggregateDirectCountDistinctUpdate {
            non_null_rows: aggregate_direct_count_distinct_update_utf8_dictionary(
                row_ids,
                values,
                value_nulls.as_deref(),
                row_nulls.as_deref(),
                row_indices,
                distinct_values,
            )?,
            dense_integer_preunion_used: false,
        }),
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            Ok(AggregateDirectCountDistinctUpdate {
                non_null_rows: aggregate_direct_count_distinct_update_materialized(
                    values,
                    row_indices,
                    distinct_values,
                )?,
                dense_integer_preunion_used: false,
            })
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_count_distinct_update_bool_report(
    values: &[bool],
    row_nulls: Option<&[bool]>,
    row_indices: Option<&[usize]>,
    distinct_values: &mut AggregateDistinctSet,
) -> Result<AggregateDirectCountDistinctUpdate> {
    aggregate_direct_count_distinct_update_slice(
        values,
        row_nulls,
        row_indices,
        distinct_values,
        AggregateDistinctValue::Boolean,
    )?;
    Ok(AggregateDirectCountDistinctUpdate {
        non_null_rows: aggregate_direct_count_distinct_non_null_rows(
            values.len(),
            row_nulls,
            row_indices,
        )?,
        dense_integer_preunion_used: false,
    })
}

