#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_interned_utf8_key(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
    string_interner: &mut AggregateStringInterner,
    label: &str,
) -> Result<u64> {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => string_interner.intern_arc(aggregate_utf8_dictionary_value_arc(
            row_ids,
            values,
            value_nulls.as_deref(),
            row_nulls.as_deref(),
            row_index,
        )?),
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            let value = values.get(row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex aggregate direct {label} row index was out of bounds; no fallback execution was attempted"
                ))
            })?;
            let StatValue::Utf8(value) = value else {
                return Err(ShardLoomError::InvalidOperation(format!(
                    "local Vortex aggregate direct {label} requires UTF-8 input, got {}; no fallback execution was attempted",
                    value.dtype().as_str()
                )));
            };
            string_interner.intern(value)
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => {
            Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex aggregate direct {label} requires UTF-8 input; no fallback execution was attempted"
            )))
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_utf8_dictionary_interner_ids(
    accessor: &AggregateDirectColumnAccessor,
    string_interner: &mut AggregateStringInterner,
) -> Result<Option<Vec<u64>>> {
    let AggregateDirectColumnAccessor::Utf8Dictionary {
        values,
        value_nulls,
        row_nulls,
        ..
    } = accessor
    else {
        return Ok(None);
    };
    if !aggregate_utf8_dictionary_value_nulls_are_absent(
        value_nulls.as_deref(),
        row_nulls.as_deref(),
    ) {
        return Ok(None);
    }
    string_interner.reserve(values.len(), "numeric-minute-string dictionary interner")?;
    values
        .iter()
        .map(|value| string_interner.intern_arc(std::sync::Arc::clone(value)))
        .collect::<Result<Vec<_>>>()
        .map(Some)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_utf8_dictionary_bound_id(
    accessor: &AggregateDirectColumnAccessor,
    dictionary_string_ids: &[u64],
    row_index: usize,
) -> Result<u64> {
    let AggregateDirectColumnAccessor::Utf8Dictionary {
        row_ids,
        values,
        value_nulls,
        row_nulls,
        ..
    } = accessor
    else {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate dictionary-bound UTF-8 key requires a dictionary accessor; no fallback execution was attempted"
                .to_string(),
        ));
    };
    if aggregate_utf8_dictionary_row_has_null(
        row_ids,
        values.len(),
        value_nulls.as_deref(),
        row_nulls.as_deref(),
        row_index,
    )? {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate dictionary-bound UTF-8 key requires a non-null dictionary value; no fallback execution was attempted"
                .to_string(),
        ));
    }
    let id = row_ids.get(row_index).copied().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex aggregate dictionary-bound UTF-8 row index was out of bounds; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    dictionary_string_ids
        .get(usize::try_from(id).map_err(|_| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate dictionary-bound UTF-8 dictionary id exceeded usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?)
        .copied()
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate dictionary-bound UTF-8 dictionary id was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })
}

#[cfg(feature = "vortex-local-primitives")]
fn string_topk_candidate_code_flags(
    dictionary_string_ids: &[u64],
    candidate_ids: &rustc_hash::FxHashSet<u64>,
    _label: &str,
) -> Vec<bool> {
    let mut flags = Vec::with_capacity(dictionary_string_ids.len());
    for value_id in dictionary_string_ids {
        flags.push(candidate_ids.contains(value_id));
    }
    flags
}

#[cfg(feature = "vortex-local-primitives")]
fn string_topk_candidate_row_count(
    row_ids: &[u32],
    candidate_code_flags: &[bool],
    row_indices: Option<&[usize]>,
    label: &str,
) -> Result<usize> {
    let mut count = 0usize;
    let mut visit_row = |row_index: usize| -> Result<()> {
        let code = row_ids.get(row_index).copied().ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex {label} row id was missing; no fallback execution was attempted"
            ))
        })?;
        let code_index = usize::try_from(code).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex {label} dictionary code overflowed usize: {error}; no fallback execution was attempted"
            ))
        })?;
        if candidate_code_flags.get(code_index).copied().ok_or_else(|| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex {label} candidate code exceeded candidate flag count; no fallback execution was attempted"
            ))
        })? {
            count = count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(format!(
                    "local Vortex {label} candidate row count overflowed usize"
                ))
            })?;
        }
        Ok(())
    };
    if let Some(row_indices) = row_indices {
        for &row_index in row_indices {
            visit_row(row_index)?;
        }
    } else {
        for row_index in 0..row_ids.len() {
            visit_row(row_index)?;
        }
    }
    Ok(count)
}

#[cfg(feature = "vortex-local-primitives")]
fn string_candidate_signatures_from_ids(
    candidate_ids: &rustc_hash::FxHashSet<u64>,
    string_interner: &AggregateStringInterner,
    label: &str,
) -> Result<rustc_hash::FxHashSet<StringCandidateSignature>> {
    let mut signatures = rustc_hash::FxHashSet::default();
    reserve_hash_set_capacity(&mut signatures, candidate_ids.len(), label)?;
    for value_id in candidate_ids {
        signatures.insert(StringCandidateSignature::from_str(
            string_interner.value(*value_id)?,
        ));
    }
    Ok(signatures)
}

#[cfg(feature = "vortex-local-primitives")]
fn string_topk_candidate_code_ids_from_values(
    values: &[std::sync::Arc<str>],
    candidate_ids: &rustc_hash::FxHashSet<u64>,
    candidate_signatures: Option<&rustc_hash::FxHashSet<StringCandidateSignature>>,
    string_interner: &AggregateStringInterner,
) -> Vec<Option<u64>> {
    let mut ids = Vec::with_capacity(values.len());
    for value in values {
        if let Some(candidate_signatures) = candidate_signatures
            && !candidate_signatures.contains(&StringCandidateSignature::from_str(value.as_ref()))
        {
            ids.push(None);
            continue;
        }
        let Some(value_id) = string_interner.id(value.as_ref()) else {
            ids.push(None);
            continue;
        };
        ids.push(candidate_ids.contains(&value_id).then_some(value_id));
    }
    ids
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_url_domain_key(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
) -> Result<Option<&str>> {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => {
            let Some(value) = aggregate_utf8_dictionary_value_opt(
                row_ids,
                values,
                value_nulls.as_deref(),
                row_nulls.as_deref(),
                row_index,
            )?
            else {
                return Ok(None);
            };
            Ok(Some(aggregate_url_domain_str(value)))
        }
        _ => Ok(None),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn dictionary_value_counts_for_rows(
    row_ids: &[u32],
    value_count: usize,
    row_indices: Option<&[usize]>,
) -> Result<Vec<u64>> {
    let mut counts = vec![0_u64; value_count];
    let mut add_id = |id: u32| -> Result<()> {
        let index = usize::try_from(id).map_err(|_| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary id exceeded usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let count = counts.get_mut(index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary id was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        *count = count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary count overflowed u64".to_string(),
            )
        })?;
        Ok(())
    };
    if let Some(row_indices) = row_indices {
        for row_index in row_indices {
            let id = row_ids.get(*row_index).copied().ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate chunk-dictionary selected row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            })?;
            add_id(id)?;
        }
    } else {
        for &id in row_ids {
            add_id(id)?;
        }
    }
    Ok(counts)
}

#[cfg(feature = "vortex-local-primitives")]
fn dictionary_value_counts_for_mask(
    row_ids: &[u32],
    value_count: usize,
    mask: &vortex::mask::Mask,
) -> Result<Vec<u64>> {
    if mask.len() != row_ids.len() {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate dictionary mask length did not match rows; no fallback execution was attempted"
                .to_string(),
        ));
    }
    let mut counts = vec![0_u64; value_count];
    for (row_index, mask_selected) in mask.iter().enumerate() {
        if !mask_selected {
            continue;
        }
        let id = row_ids.get(row_index).copied().ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary masked row index was out of bounds; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let index = usize::try_from(id).map_err(|_| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary masked id exceeded usize; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let count = counts.get_mut(index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary masked id was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        *count = count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate chunk-dictionary masked count overflowed u64".to_string(),
            )
        })?;
    }
    Ok(counts)
}

#[cfg(feature = "vortex-local-primitives")]
fn transformed_dictionary_code_pair_estimated_space(
    group_dictionary_values: usize,
    measure_dictionary_values: usize,
) -> usize {
    group_dictionary_values.saturating_mul(measure_dictionary_values)
}

#[cfg(feature = "vortex-local-primitives")]
fn transformed_dictionary_code_pair_partial_admitted(
    selected_rows: usize,
    estimated_pair_space: usize,
) -> bool {
    if selected_rows == 0 || estimated_pair_space == 0 {
        return true;
    }
    if selected_rows < 4_096 {
        return true;
    }
    if estimated_pair_space <= 1_048_576 {
        return true;
    }
    estimated_pair_space <= selected_rows / 16
}

#[cfg(feature = "vortex-local-primitives")]
fn dictionary_value_counts_and_null_count_for_rows(
    row_ids: &[u32],
    value_count: usize,
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    row_indices: Option<&[usize]>,
) -> Result<(Vec<u64>, u64)> {
    aggregate_utf8_dictionary_value_nulls_match_len(
        value_count,
        value_nulls,
        row_ids.len(),
        row_nulls,
    )?;
    if aggregate_utf8_dictionary_value_nulls_are_absent(value_nulls, row_nulls) {
        return Ok((
            dictionary_value_counts_for_rows(row_ids, value_count, row_indices)?,
            0,
        ));
    }
    let mut counts = vec![0_u64; value_count];
    let mut null_count = 0_u64;
    let mut add_row = |row_index: usize| -> Result<()> {
        if aggregate_utf8_dictionary_row_has_null(
            row_ids,
            value_count,
            value_nulls,
            row_nulls,
            row_index,
        )? {
            null_count = null_count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate dictionary null count overflowed u64".to_string(),
                )
            })?;
            return Ok(());
        }
        let index = aggregate_utf8_dictionary_code_index(row_ids, row_index)?;
        let count = counts.get_mut(index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate dictionary code referenced a missing value; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        *count = count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex aggregate dictionary count overflowed u64".to_string(),
            )
        })?;
        Ok(())
    };
    if let Some(row_indices) = row_indices {
        for &row_index in row_indices {
            add_row(row_index)?;
        }
    } else {
        for row_index in 0..row_ids.len() {
            add_row(row_index)?;
        }
    }
    Ok((counts, null_count))
}

