#[cfg(feature = "vortex-local-primitives")]
fn aggregate_utf8_dictionary_row_has_null(
    row_ids: &[u32],
    values_len: usize,
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    row_index: usize,
) -> Result<bool> {
    if row_nulls
        .and_then(|nulls| nulls.get(row_index))
        .copied()
        .unwrap_or(false)
    {
        return Ok(true);
    }
    let id = row_ids.get(row_index).copied().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary null check row index was out of bounds; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    let value_index = usize::try_from(id).map_err(|_| {
        ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary null check id exceeded usize; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    if value_index >= values_len {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary null check id was missing; no fallback execution was attempted"
                .to_string(),
        ));
    }
    Ok(value_nulls
        .and_then(|nulls| nulls.get(value_index))
        .copied()
        .unwrap_or(false))
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_utf8_dictionary_rows_are_non_null(
    row_ids: &[u32],
    values_len: usize,
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
    row_indices: Option<&[usize]>,
) -> bool {
    if aggregate_utf8_dictionary_value_nulls_are_absent(value_nulls, row_nulls) {
        return true;
    }
    let check_row = |row_index: usize| {
        aggregate_utf8_dictionary_row_has_null(
            row_ids,
            values_len,
            value_nulls,
            row_nulls,
            row_index,
        )
        .is_ok_and(|is_null| !is_null)
    };
    if let Some(row_indices) = row_indices {
        row_indices.iter().copied().all(check_row)
    } else {
        (0..row_ids.len()).all(check_row)
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_utf8_dictionary_code_index(row_ids: &[u32], row_index: usize) -> Result<usize> {
    let id = row_ids.get(row_index).copied().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary code row index was out of bounds; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    usize::try_from(id).map_err(|_| {
        ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary code exceeded usize; no fallback execution was attempted"
                .to_string(),
        )
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_utf8_dictionary_value_nulls_are_absent(
    value_nulls: Option<&[bool]>,
    row_nulls: Option<&[bool]>,
) -> bool {
    value_nulls.is_none_or(|nulls| !nulls.iter().any(|is_null| *is_null))
        && row_nulls.is_none_or(|nulls| !nulls.iter().any(|is_null| *is_null))
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_utf8_dictionary_value_nulls_match_len(
    values_len: usize,
    value_nulls: Option<&[bool]>,
    row_ids_len: usize,
    row_nulls: Option<&[bool]>,
) -> Result<()> {
    if let Some(value_nulls) = value_nulls
        && value_nulls.len() != values_len
    {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary value validity width did not match values; no fallback execution was attempted"
                .to_string(),
        ));
    }
    if let Some(row_nulls) = row_nulls
        && row_nulls.len() != row_ids_len
    {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate direct UTF-8 dictionary row validity width did not match rows; no fallback execution was attempted"
                .to_string(),
        ));
    }
    Ok(())
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_distinct_value(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
) -> Result<AggregateDistinctValue> {
    if let Some(value) = aggregate_direct_boolean_distinct_value(accessor, row_index) {
        return value;
    }
    if let Some(values) = accessor.u64_values() {
        return values
            .get(row_index)
            .copied()
            .map(AggregateDistinctValue::UInt64)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate direct uint64 key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            });
    }
    if let Some(values) = accessor.i64_values() {
        return values
            .get(row_index)
            .copied()
            .map(AggregateDistinctValue::Int64)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate direct int64 key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            });
    }
    if let Some(values) = accessor.f64_values() {
        return values
            .get(row_index)
            .copied()
            .map(|value| AggregateDistinctValue::Float64Bits(value.to_bits()))
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate direct float64 key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            });
    }
    match accessor {
        AggregateDirectColumnAccessor::NullableUInt64 { values, row_nulls } => {
            aggregate_nullable_primitive_value(values, row_nulls, row_index, "uint64 distinct")
                .map(|value| {
                    value.map_or(AggregateDistinctValue::Null, AggregateDistinctValue::UInt64)
                })
        }
        AggregateDirectColumnAccessor::NullableInt64 { values, row_nulls } => {
            aggregate_nullable_primitive_value(values, row_nulls, row_index, "int64 distinct")
                .map(|value| {
                    value.map_or(AggregateDistinctValue::Null, AggregateDistinctValue::Int64)
                })
        }
        AggregateDirectColumnAccessor::NullableFloat64 { values, row_nulls } => {
            aggregate_nullable_primitive_value(values, row_nulls, row_index, "float64 distinct")
                .map(|value| {
                    value.map_or(AggregateDistinctValue::Null, |value| {
                        AggregateDistinctValue::Float64Bits(value.to_bits())
                    })
                })
        }
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => aggregate_utf8_dictionary_arc_value_opt(
            row_ids,
            values,
            value_nulls.as_deref(),
            row_nulls.as_deref(),
            row_index,
        )
        .map(|value| {
            value.map_or(AggregateDistinctValue::Null, |value| {
                AggregateDistinctValue::Utf8(std::sync::Arc::clone(value))
            })
        }),
        AggregateDirectColumnAccessor::Materialized { values, .. } => values
            .get(row_index)
            .map(AggregateDistinctValue::from)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate materialized key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::Float64(_) => unreachable!(
            "direct primitive accessors are handled before aggregate_direct_distinct_value match"
        ),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_boolean_distinct_value(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
) -> Option<Result<AggregateDistinctValue>> {
    match accessor {
        AggregateDirectColumnAccessor::Boolean(values) => Some(
            values
                .get(row_index)
                .copied()
                .map(AggregateDistinctValue::Boolean)
                .ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex aggregate direct boolean key row index was out of bounds; no fallback execution was attempted"
                            .to_string(),
                    )
                }),
        ),
        AggregateDirectColumnAccessor::NullableBoolean { values, row_nulls } => {
            Some(
                aggregate_nullable_primitive_value(values, row_nulls, row_index, "boolean distinct")
                    .map(|value| {
                        value.map_or(AggregateDistinctValue::Null, AggregateDistinctValue::Boolean)
                    }),
            )
        }
        _ => None,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_distinct_value_for_group_key(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
    string_interner: &mut AggregateStringInterner,
) -> Result<AggregateDistinctValue> {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => {
            let Some(value) = aggregate_utf8_dictionary_value_opt(
                row_ids,
                values,
                value_nulls.as_deref(),
                row_nulls.as_deref(),
                row_index,
            )?
            else {
                return Ok(AggregateDistinctValue::Null);
            };
            Ok(AggregateDistinctValue::Utf8Interned(
                string_interner.intern(value)?,
            ))
        }
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            let value = values.get(row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate materialized group-key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            })?;
            aggregate_distinct_value_for_group_key(value, string_interner)
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => {
            aggregate_direct_distinct_value(accessor, row_index)
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_direct_distinct_value_for_group_key_existing(
    accessor: &AggregateDirectColumnAccessor,
    row_index: usize,
    string_interner: &AggregateStringInterner,
) -> Result<Option<AggregateDistinctValue>> {
    match accessor {
        AggregateDirectColumnAccessor::Utf8Dictionary {
            row_ids,
            values,
            value_nulls,
            row_nulls,
            ..
        } => {
            let Some(value) = aggregate_utf8_dictionary_value_opt(
                row_ids,
                values,
                value_nulls.as_deref(),
                row_nulls.as_deref(),
                row_index,
            )?
            else {
                return Ok(Some(AggregateDistinctValue::Null));
            };
            Ok(string_interner
                .id(value)
                .map(AggregateDistinctValue::Utf8Interned))
        }
        AggregateDirectColumnAccessor::Materialized { values, .. } => {
            let value = values.get(row_index).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate existing materialized group-key row index was out of bounds; no fallback execution was attempted"
                        .to_string(),
                )
            })?;
            Ok(aggregate_distinct_value_for_group_key_existing(
                value,
                string_interner,
            ))
        }
        AggregateDirectColumnAccessor::UInt64(_)
        | AggregateDirectColumnAccessor::Boolean(_)
        | AggregateDirectColumnAccessor::NullableBoolean { .. }
        | AggregateDirectColumnAccessor::NullableUInt64 { .. }
        | AggregateDirectColumnAccessor::Int64(_)
        | AggregateDirectColumnAccessor::NullableInt64 { .. }
        | AggregateDirectColumnAccessor::Float64(_)
        | AggregateDirectColumnAccessor::NullableFloat64 { .. } => {
            aggregate_direct_distinct_value(accessor, row_index).map(Some)
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
#[allow(clippy::cast_precision_loss)]
fn aggregate_add_offset(value: &StatValue, offset: i64) -> Result<StatValue> {
    match value {
        StatValue::Int64(value) => value
            .checked_add(offset)
            .map(StatValue::Int64)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate additive group expression overflowed int64; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        StatValue::UInt64(value) if offset >= 0 => value
            .checked_add(offset.cast_unsigned())
            .map(StatValue::UInt64)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate additive group expression overflowed uint64; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        StatValue::UInt64(value) => value
            .checked_sub(offset.unsigned_abs())
            .map(StatValue::UInt64)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate additive group expression underflowed uint64; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        StatValue::Float64(value) => {
            let adjusted = *value + offset as f64;
            if adjusted.is_finite() {
                Ok(StatValue::Float64(adjusted))
            } else {
                Err(ShardLoomError::InvalidOperation(
                    "local Vortex aggregate additive group expression produced non-finite float64; no fallback execution was attempted"
                        .to_string(),
                ))
            }
        }
        other => Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex aggregate additive group expression requires numeric input, got {}; no fallback execution was attempted",
            other.dtype().as_str()
        ))),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_extract_minute(value: &StatValue) -> Result<StatValue> {
    match value {
        StatValue::Int64(value) => Ok(StatValue::Int64(value.rem_euclid(3600) / 60)),
        StatValue::UInt64(value) => Ok(StatValue::UInt64((value % 3600) / 60)),
        StatValue::Utf8(value) => parse_timestamp_minute(value)
            .map(|minute| StatValue::UInt64(u64::from(minute)))
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate extract-minute expression requires a parseable timestamp string; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        other => Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex aggregate extract-minute expression requires timestamp-compatible input, got {}; no fallback execution was attempted",
            other.dtype().as_str()
        ))),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_date_trunc_minute(value: &StatValue) -> Result<StatValue> {
    match value {
        StatValue::Int64(value) => Ok(StatValue::Int64(value.div_euclid(60) * 60)),
        StatValue::UInt64(value) => Ok(StatValue::UInt64((value / 60) * 60)),
        StatValue::Utf8(value) => truncate_timestamp_string_to_minute(value)
            .map(StatValue::Utf8)
            .ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex aggregate date-trunc-minute expression requires a parseable timestamp string; no fallback execution was attempted"
                        .to_string(),
                )
            }),
        other => Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex aggregate date-trunc-minute expression requires timestamp-compatible input, got {}; no fallback execution was attempted",
            other.dtype().as_str()
        ))),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn parse_timestamp_minute(value: &str) -> Option<u8> {
    let time = value.split_once('T').map_or_else(
        || value.split_whitespace().nth(1),
        |(_date, time)| Some(time),
    )?;
    let minute = time.split(':').nth(1)?.parse::<u8>().ok()?;
    (minute < 60).then_some(minute)
}

#[cfg(feature = "vortex-local-primitives")]
fn truncate_timestamp_string_to_minute(value: &str) -> Option<String> {
    let second_colon = value.match_indices(':').nth(1)?.0;
    let mut out = value[..second_colon].to_string();
    out.push_str(":00");
    Some(out)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_url_domain(value: &StatValue) -> Result<StatValue> {
    let StatValue::Utf8(value) = value else {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate URL-domain expression requires UTF-8 input; no fallback execution was attempted"
                .to_string(),
        ));
    };
    Ok(StatValue::Utf8(
        crate::url_domain::shardloom_url_domain(value).to_string(),
    ))
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_url_domain_str(value: &str) -> &str {
    crate::url_domain::shardloom_url_domain(value)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_case_search_adv_zero_referer_else_empty(
    referer: &StatValue,
    extra_values: &[&StatValue],
) -> Result<StatValue> {
    if extra_values.len() != 2 {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex aggregate CASE search/advertising expression requires SearchEngineID and AdvEngineID auxiliary columns; no fallback execution was attempted"
                .to_string(),
        ));
    }
    let search_engine_id = stat_value_to_i64(extra_values[0])?;
    let adv_engine_id = stat_value_to_i64(extra_values[1])?;
    if search_engine_id == 0 && adv_engine_id == 0 {
        match referer {
            StatValue::Utf8(value) => Ok(StatValue::Utf8(value.clone())),
            other => Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex aggregate CASE referer expression requires UTF-8 referer input, got {}; no fallback execution was attempted",
                other.dtype().as_str()
            ))),
        }
    } else {
        Ok(StatValue::Utf8(String::new()))
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_row_matches_having(
    row: &serde_json::Map<String, serde_json::Value>,
    having: &[VortexAggregateHavingExpr],
) -> Result<bool> {
    for expression in having {
        let Some(left) = row.get(&expression.column) else {
            return Err(ShardLoomError::InvalidOperation(format!(
                "local Vortex aggregate HAVING column '{}' was not present in the result row; no fallback execution was attempted",
                expression.column
            )));
        };
        let right = aggregate_having_value_json(&expression.value);
        let ordering = compare_json_values(left, &right);
        if !aggregate_having_ordering_matches(ordering, expression.op) {
            return Ok(false);
        }
    }
    Ok(true)
}

#[cfg(feature = "vortex-local-primitives")]
fn aggregate_having_value_json(value: &str) -> serde_json::Value {
    if let Ok(value) = value.parse::<i64>() {
        return serde_json::Value::Number(value.into());
    }
    if let Ok(value) = value.parse::<u64>() {
        return serde_json::Value::Number(value.into());
    }
    if let Ok(value) = value.parse::<f64>()
        && let Some(number) = serde_json::Number::from_f64(value)
    {
        return serde_json::Value::Number(number);
    }
    match value {
        "true" => serde_json::Value::Bool(true),
        "false" => serde_json::Value::Bool(false),
        _ => serde_json::Value::String(value.to_string()),
    }
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone)]
struct SimpleAggregateState {
    function: SimpleAggregateFunction,
    column_index: Option<usize>,
    alias: String,
    count: u64,
    sum: f64,
    min: Option<StatValue>,
    max: Option<StatValue>,
    distinct_values: AggregateDistinctSet,
    argument_offset: Option<i64>,
    value_transform: AggregateValueTransform,
}

#[cfg(feature = "vortex-local-primitives")]
#[derive(Clone, Debug, Eq, PartialEq, Hash)]
enum AggregateDistinctValue {
    Null,
    Boolean(bool),
    Int64(i64),
    UInt64(u64),
    Float64Bits(u64),
    Utf8(std::sync::Arc<str>),
    Utf8Interned(u64),
}

#[cfg(feature = "vortex-local-primitives")]
type AggregateDistinctSet = rustc_hash::FxHashSet<AggregateDistinctValue>;

#[cfg(feature = "vortex-local-primitives")]
impl From<&StatValue> for AggregateDistinctValue {
    fn from(value: &StatValue) -> Self {
        match value {
            StatValue::Null => Self::Null,
            StatValue::Boolean(value) => Self::Boolean(*value),
            StatValue::Int64(value) => Self::Int64(*value),
            StatValue::UInt64(value) => Self::UInt64(*value),
            StatValue::Float64(value) => Self::Float64Bits(value.to_bits()),
            StatValue::Utf8(value) => Self::Utf8(std::sync::Arc::<str>::from(value.as_str())),
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
impl AggregateDistinctValue {
    fn estimated_storage_bytes(&self) -> usize {
        match self {
            Self::Null => 1,
            Self::Boolean(_) => std::mem::size_of::<bool>(),
            Self::Int64(_) => std::mem::size_of::<i64>(),
            Self::UInt64(_) | Self::Float64Bits(_) | Self::Utf8Interned(_) => {
                std::mem::size_of::<u64>()
            }
            Self::Utf8(value) => {
                std::mem::size_of::<std::sync::Arc<str>>().saturating_add(value.len())
            }
        }
    }

    fn to_stat_value(&self, interner: &AggregateStringInterner) -> Result<StatValue> {
        match self {
            Self::Null => Ok(StatValue::Null),
            Self::Boolean(value) => Ok(StatValue::Boolean(*value)),
            Self::Int64(value) => Ok(StatValue::Int64(*value)),
            Self::UInt64(value) => Ok(StatValue::UInt64(*value)),
            Self::Float64Bits(value) => Ok(StatValue::Float64(f64::from_bits(*value))),
            Self::Utf8(value) => Ok(StatValue::Utf8(value.to_string())),
            Self::Utf8Interned(id) => Ok(StatValue::Utf8(interner.value(*id)?.to_string())),
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
impl SimpleAggregateState {
    fn new(
        function: SimpleAggregateFunction,
        column_index: Option<usize>,
        alias: String,
        argument_offset: Option<i64>,
        value_transform: AggregateValueTransform,
    ) -> Self {
        Self {
            function,
            column_index,
            alias,
            count: 0,
            sum: 0.0,
            min: None,
            max: None,
            distinct_values: AggregateDistinctSet::default(),
            argument_offset,
            value_transform,
        }
    }

    fn update(&mut self, columns: &[Vec<StatValue>], rows: usize) -> Result<()> {
        let Some(column_index) = self.column_index else {
            self.count = self.count.checked_add(usize_to_u64(rows)?).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate count overflowed u64".to_string(),
                )
            })?;
            return Ok(());
        };
        let values = columns.get(column_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate column index was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        if rows > values.len() {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate requested more rows than the materialized chunk contains; no fallback execution was attempted"
                    .to_string(),
            ));
        }
        for value in values.iter().take(rows) {
            let transformed_value = self.value_transform.apply(value)?;
            self.update_transformed_value(&transformed_value)?;
        }
        Ok(())
    }

    fn update_row(&mut self, columns: &[Vec<StatValue>], row_index: usize) -> Result<()> {
        let Some(column_index) = self.column_index else {
            self.count = self.count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate count overflowed u64".to_string(),
                )
            })?;
            return Ok(());
        };
        let values = columns.get(column_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate column index was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let value = values.get(row_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate row index exceeded materialized chunk rows; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let transformed_value = self.value_transform.apply(value)?;
        self.update_transformed_value(&transformed_value)
    }

    fn update_direct_row_from_accessors(
        &mut self,
        accessors: &[AggregateDirectColumnAccessor],
        row_index: usize,
        chunk_rows: usize,
    ) -> Result<()> {
        let Some(column_index) = self.column_index else {
            if row_index >= chunk_rows {
                return Err(ShardLoomError::InvalidOperation(
                    "local Vortex grouped aggregate direct count row index exceeded chunk rows; no fallback execution was attempted"
                        .to_string(),
                ));
            }
            self.count = self.count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex grouped aggregate direct count overflowed u64".to_string(),
                )
            })?;
            return Ok(());
        };
        let accessor = accessors.get(column_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex grouped aggregate direct measure column index was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        match self.function {
            SimpleAggregateFunction::Count
            | SimpleAggregateFunction::Min
            | SimpleAggregateFunction::Max => {
                let Some(value) = self.direct_stat_measure_value(accessor, row_index)? else {
                    return Ok(());
                };
                self.update_transformed_value(&value)
            }
            SimpleAggregateFunction::CountDistinct => {
                if !matches!(self.value_transform, AggregateValueTransform::Identity) {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex grouped aggregate direct count-distinct only admits identity values; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                let value = aggregate_direct_distinct_value(accessor, row_index)?;
                if matches!(value, AggregateDistinctValue::Null) {
                    return Ok(());
                }
                self.count = self.count.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex grouped aggregate direct count-distinct row count overflowed u64"
                            .to_string(),
                    )
                })?;
                self.distinct_values.insert(value);
                Ok(())
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                let Some(mut numeric) = self.direct_numeric_measure_value(accessor, row_index)?
                else {
                    return Ok(());
                };
                if let Some(offset) = self.argument_offset {
                    numeric += int64_stat_to_float64(offset);
                }
                if !numeric.is_finite() {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex grouped aggregate direct numeric update encountered non-finite value; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                self.count = self.count.checked_add(1).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex grouped aggregate direct numeric count overflowed u64"
                            .to_string(),
                    )
                })?;
                self.sum += numeric;
                if !self.sum.is_finite() {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex grouped aggregate direct numeric sum became non-finite; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                Ok(())
            }
        }
    }

    fn direct_update_admitted(
        &self,
        accessors: &[AggregateDirectColumnAccessor],
        row_indices: Option<&[usize]>,
    ) -> bool {
        let Some(column_index) = self.column_index else {
            return self.function == SimpleAggregateFunction::Count
                && matches!(self.value_transform, AggregateValueTransform::Identity);
        };
        let Some(accessor) = accessors.get(column_index) else {
            return false;
        };
        match self.function {
            SimpleAggregateFunction::Count => matches!(
                self.value_transform,
                AggregateValueTransform::Identity | AggregateValueTransform::Length
            ),
            SimpleAggregateFunction::CountDistinct => {
                matches!(self.value_transform, AggregateValueTransform::Identity)
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                self.direct_numeric_measure_admitted(accessor, row_indices)
            }
            SimpleAggregateFunction::Min | SimpleAggregateFunction::Max => {
                self.direct_stat_measure_admitted(accessor, row_indices)
            }
        }
    }

    fn direct_dictionary_count_distinct_admitted(
        &self,
        accessors: &[AggregateDirectColumnAccessor],
    ) -> bool {
        let Some(column_index) = self.column_index else {
            return false;
        };
        self.function == SimpleAggregateFunction::CountDistinct
            && matches!(self.value_transform, AggregateValueTransform::Identity)
            && matches!(
                accessors.get(column_index),
                Some(AggregateDirectColumnAccessor::Utf8Dictionary { .. })
            )
    }

    fn transformed_dictionary_general_measure_admitted(
        &self,
        dictionary_column_index: usize,
    ) -> bool {
        if self.argument_offset.is_some() {
            return false;
        }
        match self.function {
            SimpleAggregateFunction::Count => self.column_index.is_none_or(|column_index| {
                column_index == dictionary_column_index
                    && matches!(
                        self.value_transform,
                        AggregateValueTransform::Identity | AggregateValueTransform::Length
                    )
            }),
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                self.column_index == Some(dictionary_column_index)
                    && matches!(self.value_transform, AggregateValueTransform::Length)
            }
            SimpleAggregateFunction::Min | SimpleAggregateFunction::Max => {
                self.column_index == Some(dictionary_column_index)
                    && matches!(
                        self.value_transform,
                        AggregateValueTransform::Identity | AggregateValueTransform::Length
                    )
            }
            SimpleAggregateFunction::CountDistinct => false,
        }
    }

    #[allow(clippy::cast_precision_loss)]
    fn update_weighted_utf8_dictionary_value(
        &mut self,
        dictionary_column_index: usize,
        value: &str,
        weight: u64,
    ) -> Result<bool> {
        if weight == 0 {
            return Ok(false);
        }
        if !self.transformed_dictionary_general_measure_admitted(dictionary_column_index) {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary general aggregate reached a non-admitted measure; no fallback execution was attempted"
                    .to_string(),
            ));
        }
        let add_weight = |count: &mut u64| -> Result<()> {
            *count = count.checked_add(weight).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex transformed-dictionary weighted aggregate count overflowed u64"
                        .to_string(),
                )
            })?;
            Ok(())
        };
        match self.function {
            SimpleAggregateFunction::Count => {
                add_weight(&mut self.count)?;
                Ok(false)
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                let numeric = match self.value_transform {
                    AggregateValueTransform::Length => value.len() as f64,
                    AggregateValueTransform::Identity
                    | AggregateValueTransform::ConstantInt(_)
                    | AggregateValueTransform::AddOffset(_)
                    | AggregateValueTransform::ExtractMinute
                    | AggregateValueTransform::DateTruncMinute
                    | AggregateValueTransform::UrlDomain
                    | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
                        return Err(ShardLoomError::InvalidOperation(
                            "local Vortex transformed-dictionary weighted numeric aggregate only admits UTF-8 length; no fallback execution was attempted"
                                .to_string(),
                        ));
                    }
                };
                add_weight(&mut self.count)?;
                self.sum += numeric * uint64_stat_to_float64(weight);
                if !self.sum.is_finite() {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex transformed-dictionary weighted numeric aggregate became non-finite; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                Ok(false)
            }
            SimpleAggregateFunction::Min => {
                if matches!(self.value_transform, AggregateValueTransform::Identity) {
                    add_weight(&mut self.count)?;
                    return self.update_weighted_utf8_identity_min(value);
                }
                let transformed = self.weighted_utf8_dictionary_stat_value(value)?;
                add_weight(&mut self.count)?;
                self.min = Some(simple_aggregate_min_value(self.min.take(), &transformed)?);
                Ok(false)
            }
            SimpleAggregateFunction::Max => {
                if matches!(self.value_transform, AggregateValueTransform::Identity) {
                    add_weight(&mut self.count)?;
                    return self.update_weighted_utf8_identity_max(value);
                }
                let transformed = self.weighted_utf8_dictionary_stat_value(value)?;
                add_weight(&mut self.count)?;
                self.max = Some(simple_aggregate_max_value(self.max.take(), &transformed)?);
                Ok(false)
            }
            SimpleAggregateFunction::CountDistinct => Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary weighted aggregate does not admit count-distinct; no fallback execution was attempted"
                    .to_string(),
            )),
        }
    }

    fn update_weighted_utf8_identity_min(&mut self, value: &str) -> Result<bool> {
        match self.min.as_ref() {
            None => {
                self.min = Some(StatValue::Utf8(value.to_string()));
                Ok(true)
            }
            Some(StatValue::Utf8(current)) if value < current.as_str() => {
                self.min = Some(StatValue::Utf8(value.to_string()));
                Ok(true)
            }
            Some(StatValue::Utf8(_)) => Ok(true),
            Some(_) => Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary weighted UTF-8 min reached incompatible current state; no fallback execution was attempted"
                    .to_string(),
            )),
        }
    }

    fn update_weighted_utf8_identity_max(&mut self, value: &str) -> Result<bool> {
        match self.max.as_ref() {
            None => {
                self.max = Some(StatValue::Utf8(value.to_string()));
                Ok(true)
            }
            Some(StatValue::Utf8(current)) if value > current.as_str() => {
                self.max = Some(StatValue::Utf8(value.to_string()));
                Ok(true)
            }
            Some(StatValue::Utf8(_)) => Ok(true),
            Some(_) => Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary weighted UTF-8 max reached incompatible current state; no fallback execution was attempted"
                    .to_string(),
            )),
        }
    }

    fn weighted_utf8_dictionary_stat_value(&self, value: &str) -> Result<StatValue> {
        match self.value_transform {
            AggregateValueTransform::Identity => Ok(StatValue::Utf8(value.to_string())),
            AggregateValueTransform::Length => Ok(StatValue::UInt64(usize_to_u64(value.len())?)),
            AggregateValueTransform::ConstantInt(_)
            | AggregateValueTransform::AddOffset(_)
            | AggregateValueTransform::ExtractMinute
            | AggregateValueTransform::DateTruncMinute
            | AggregateValueTransform::UrlDomain
            | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
                Err(ShardLoomError::InvalidOperation(
                    "local Vortex transformed-dictionary weighted stat aggregate reached an unsupported transform; no fallback execution was attempted"
                        .to_string(),
                ))
            }
        }
    }

    fn add_weighted_utf8_count(&mut self, weight: u64) -> Result<()> {
        self.count = self.count.checked_add(weight).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary weighted aggregate count overflowed u64"
                    .to_string(),
            )
        })?;
        Ok(())
    }

    fn update_weighted_utf8_dictionary_cached_transform(
        &mut self,
        dictionary_column_index: usize,
        value: &str,
        weight: u64,
        length_f64: f64,
        length_value: &StatValue,
    ) -> Result<bool> {
        if !self.transformed_dictionary_general_measure_admitted(dictionary_column_index) {
            return Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary fused aggregate reached a non-admitted measure; no fallback execution was attempted"
                    .to_string(),
            ));
        }
        match self.function {
            SimpleAggregateFunction::Count => {
                self.add_weighted_utf8_count(weight)?;
                Ok(false)
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                if !matches!(self.value_transform, AggregateValueTransform::Length) {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex transformed-dictionary fused numeric aggregate only admits UTF-8 length; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                self.add_weighted_utf8_count(weight)?;
                self.sum += length_f64 * uint64_stat_to_float64(weight);
                if !self.sum.is_finite() {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex transformed-dictionary fused numeric aggregate became non-finite; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                Ok(false)
            }
            SimpleAggregateFunction::Min => {
                let lazy_minmax = matches!(self.value_transform, AggregateValueTransform::Length);
                let transformed = match self.value_transform {
                    AggregateValueTransform::Identity => {
                        self.add_weighted_utf8_count(weight)?;
                        return self.update_weighted_utf8_identity_min(value);
                    }
                    AggregateValueTransform::Length => length_value,
                    AggregateValueTransform::ConstantInt(_)
                    | AggregateValueTransform::AddOffset(_)
                    | AggregateValueTransform::ExtractMinute
                    | AggregateValueTransform::DateTruncMinute
                    | AggregateValueTransform::UrlDomain
                    | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
                        return Err(ShardLoomError::InvalidOperation(
                            "local Vortex transformed-dictionary fused min aggregate only admits identity or UTF-8 length; no fallback execution was attempted"
                                .to_string(),
                        ));
                    }
                };
                self.add_weighted_utf8_count(weight)?;
                self.min = Some(simple_aggregate_min_value(self.min.take(), transformed)?);
                Ok(lazy_minmax)
            }
            SimpleAggregateFunction::Max => {
                let lazy_minmax = matches!(self.value_transform, AggregateValueTransform::Length);
                let transformed = match self.value_transform {
                    AggregateValueTransform::Identity => {
                        self.add_weighted_utf8_count(weight)?;
                        return self.update_weighted_utf8_identity_max(value);
                    }
                    AggregateValueTransform::Length => length_value,
                    AggregateValueTransform::ConstantInt(_)
                    | AggregateValueTransform::AddOffset(_)
                    | AggregateValueTransform::ExtractMinute
                    | AggregateValueTransform::DateTruncMinute
                    | AggregateValueTransform::UrlDomain
                    | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
                        return Err(ShardLoomError::InvalidOperation(
                            "local Vortex transformed-dictionary fused max aggregate only admits identity or UTF-8 length; no fallback execution was attempted"
                                .to_string(),
                        ));
                    }
                };
                self.add_weighted_utf8_count(weight)?;
                self.max = Some(simple_aggregate_max_value(self.max.take(), transformed)?);
                Ok(lazy_minmax)
            }
            SimpleAggregateFunction::CountDistinct => Err(ShardLoomError::InvalidOperation(
                "local Vortex transformed-dictionary fused aggregate does not admit count-distinct; no fallback execution was attempted"
                    .to_string(),
            )),
        }
    }

    fn update_direct_from_accessors(
        &mut self,
        accessors: &[AggregateDirectColumnAccessor],
        row_indices: Option<&[usize]>,
        chunk_rows: usize,
    ) -> Result<bool> {
        let Some(column_index) = self.column_index else {
            let rows = row_indices.map_or(chunk_rows, <[usize]>::len);
            self.count = self.count.checked_add(usize_to_u64(rows)?).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate direct count overflowed u64".to_string(),
                )
            })?;
            return Ok(false);
        };
        let accessor = accessors.get(column_index).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate direct column index was missing; no fallback execution was attempted"
                    .to_string(),
            )
        })?;
        let mut dense_integer_distinct_preunion_used = false;
        match self.function {
            SimpleAggregateFunction::Count => {
                let rows = aggregate_direct_non_null_row_count(accessor, row_indices)?;
                self.count = self.count.checked_add(rows).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex simple aggregate direct count overflowed u64".to_string(),
                    )
                })?;
            }
            SimpleAggregateFunction::CountDistinct => {
                let update = aggregate_direct_count_distinct_update(
                    accessor,
                    row_indices,
                    &mut self.distinct_values,
                )?;
                dense_integer_distinct_preunion_used = update.dense_integer_preunion_used;
                self.count = self.count.checked_add(update.non_null_rows).ok_or_else(|| {
                    ShardLoomError::InvalidOperation(
                        "local Vortex simple aggregate direct count-distinct row count overflowed u64"
                            .to_string(),
                    )
                })?;
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                self.update_direct_numeric_measure(accessor, row_indices)?;
            }
            SimpleAggregateFunction::Min | SimpleAggregateFunction::Max => {
                self.update_direct_stat_measure(accessor, row_indices)?;
            }
        }
        Ok(dense_integer_distinct_preunion_used)
    }

    fn direct_numeric_measure_admitted(
        &self,
        accessor: &AggregateDirectColumnAccessor,
        row_indices: Option<&[usize]>,
    ) -> bool {
        match self.value_transform {
            AggregateValueTransform::Identity => match accessor {
                AggregateDirectColumnAccessor::UInt64(_)
                | AggregateDirectColumnAccessor::NullableUInt64 { .. }
                | AggregateDirectColumnAccessor::Int64(_)
                | AggregateDirectColumnAccessor::NullableInt64 { .. }
                | AggregateDirectColumnAccessor::Float64(_)
                | AggregateDirectColumnAccessor::NullableFloat64 { .. } => true,
                AggregateDirectColumnAccessor::Materialized { values, .. } => {
                    aggregate_materialized_numeric_rows_admitted(values, row_indices)
                }
                AggregateDirectColumnAccessor::Boolean(_)
                | AggregateDirectColumnAccessor::NullableBoolean { .. }
                | AggregateDirectColumnAccessor::Utf8Dictionary { .. } => false,
            },
            AggregateValueTransform::Length => {
                aggregate_direct_utf8_rows_admitted(accessor, row_indices)
            }
            AggregateValueTransform::ConstantInt(_)
            | AggregateValueTransform::AddOffset(_)
            | AggregateValueTransform::ExtractMinute
            | AggregateValueTransform::DateTruncMinute
            | AggregateValueTransform::UrlDomain
            | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => false,
        }
    }

    fn direct_stat_measure_admitted(
        &self,
        accessor: &AggregateDirectColumnAccessor,
        row_indices: Option<&[usize]>,
    ) -> bool {
        match self.value_transform {
            AggregateValueTransform::Identity => match accessor {
                AggregateDirectColumnAccessor::Boolean(_)
                | AggregateDirectColumnAccessor::NullableBoolean { .. }
                | AggregateDirectColumnAccessor::UInt64(_)
                | AggregateDirectColumnAccessor::NullableUInt64 { .. }
                | AggregateDirectColumnAccessor::Int64(_)
                | AggregateDirectColumnAccessor::NullableInt64 { .. }
                | AggregateDirectColumnAccessor::Float64(_)
                | AggregateDirectColumnAccessor::NullableFloat64 { .. }
                | AggregateDirectColumnAccessor::Utf8Dictionary { .. } => true,
                AggregateDirectColumnAccessor::Materialized { values, .. } => {
                    aggregate_materialized_comparable_rows_admitted(values, row_indices)
                }
            },
            AggregateValueTransform::Length => {
                aggregate_direct_utf8_rows_admitted(accessor, row_indices)
            }
            AggregateValueTransform::ConstantInt(_)
            | AggregateValueTransform::AddOffset(_)
            | AggregateValueTransform::ExtractMinute
            | AggregateValueTransform::DateTruncMinute
            | AggregateValueTransform::UrlDomain
            | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => false,
        }
    }

    fn update_direct_numeric_measure(
        &mut self,
        accessor: &AggregateDirectColumnAccessor,
        row_indices: Option<&[usize]>,
    ) -> Result<()> {
        let update_row = |state: &mut Self, row_index| -> Result<()> {
            let Some(mut numeric) = state.direct_numeric_measure_value(accessor, row_index)? else {
                return Ok(());
            };
            if let Some(offset) = state.argument_offset {
                numeric += int64_stat_to_float64(offset);
            }
            if !numeric.is_finite() {
                return Err(ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate direct numeric update encountered non-finite value; no fallback execution was attempted"
                        .to_string(),
                ));
            }
            state.count = state.count.checked_add(1).ok_or_else(|| {
                ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate direct numeric count overflowed u64".to_string(),
                )
            })?;
            state.sum += numeric;
            if !state.sum.is_finite() {
                return Err(ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate direct numeric sum became non-finite; no fallback execution was attempted"
                        .to_string(),
                ));
            }
            Ok(())
        };
        if let Some(row_indices) = row_indices {
            for &row_index in row_indices {
                update_row(self, row_index)?;
            }
        } else {
            for row_index in 0..accessor.len() {
                update_row(self, row_index)?;
            }
        }
        Ok(())
    }

    fn update_direct_stat_measure(
        &mut self,
        accessor: &AggregateDirectColumnAccessor,
        row_indices: Option<&[usize]>,
    ) -> Result<()> {
        let update_row = |state: &mut Self, row_index| -> Result<()> {
            let Some(value) = state.direct_stat_measure_value(accessor, row_index)? else {
                return Ok(());
            };
            state.update_transformed_value(&value)
        };
        if let Some(row_indices) = row_indices {
            for &row_index in row_indices {
                update_row(self, row_index)?;
            }
        } else {
            for row_index in 0..accessor.len() {
                update_row(self, row_index)?;
            }
        }
        Ok(())
    }

    fn direct_numeric_measure_value(
        &self,
        accessor: &AggregateDirectColumnAccessor,
        row_index: usize,
    ) -> Result<Option<f64>> {
        match self.value_transform {
            AggregateValueTransform::Identity => aggregate_direct_numeric_value(accessor, row_index),
            AggregateValueTransform::Length => aggregate_direct_utf8_length_value(accessor, row_index),
            AggregateValueTransform::ConstantInt(_)
            | AggregateValueTransform::AddOffset(_)
            | AggregateValueTransform::ExtractMinute
            | AggregateValueTransform::DateTruncMinute
            | AggregateValueTransform::UrlDomain
            | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => {
                Err(ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate direct numeric update only admits identity numeric or UTF-8 length transforms; no fallback execution was attempted"
                        .to_string(),
                ))
            }
        }
    }

    fn direct_stat_measure_value(
        &self,
        accessor: &AggregateDirectColumnAccessor,
        row_index: usize,
    ) -> Result<Option<StatValue>> {
        let value = aggregate_direct_stat_value(accessor, row_index)?;
        if matches!(value, StatValue::Null) {
            return Ok(None);
        }
        let transformed_value = self.value_transform.apply(&value)?;
        Ok((!matches!(transformed_value, StatValue::Null)).then_some(transformed_value))
    }

    fn update_transformed_value(&mut self, transformed_value: &StatValue) -> Result<()> {
        if matches!(transformed_value, StatValue::Null) {
            return Ok(());
        }
        self.count = self.count.checked_add(1).ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate count overflowed u64".to_string(),
            )
        })?;
        match self.function {
            SimpleAggregateFunction::Count => {}
            SimpleAggregateFunction::CountDistinct => {
                self.distinct_values
                    .insert(AggregateDistinctValue::from(transformed_value));
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                let numeric = self.aggregate_numeric_value(transformed_value)?;
                if !numeric.is_finite() {
                    return Err(ShardLoomError::InvalidOperation(
                        "local Vortex simple aggregate encountered non-finite numeric value; no fallback execution was attempted"
                            .to_string(),
                    ));
                }
                self.sum += numeric;
            }
            SimpleAggregateFunction::Min => {
                self.min = Some(simple_aggregate_min_value(
                    self.min.take(),
                    transformed_value,
                )?);
            }
            SimpleAggregateFunction::Max => {
                self.max = Some(simple_aggregate_max_value(
                    self.max.take(),
                    transformed_value,
                )?);
            }
        }
        Ok(())
    }

    fn result_json(&self) -> Result<serde_json::Value> {
        match self.function {
            SimpleAggregateFunction::Count => Ok(serde_json::Value::Number(self.count.into())),
            SimpleAggregateFunction::CountDistinct => Ok(serde_json::Value::Number(
                usize_to_u64(self.distinct_values.len())?.into(),
            )),
            SimpleAggregateFunction::Sum => {
                if self.count == 0 {
                    Ok(serde_json::Value::Null)
                } else {
                    json_number_from_f64(self.sum)
                }
            }
            SimpleAggregateFunction::Avg => {
                if self.count == 0 {
                    Ok(serde_json::Value::Null)
                } else {
                    json_number_from_f64(simple_average_value(self.sum, self.count))
                }
            }
            SimpleAggregateFunction::Min => self
                .min
                .as_ref()
                .map_or(Ok(serde_json::Value::Null), stat_value_to_json_value),
            SimpleAggregateFunction::Max => self
                .max
                .as_ref()
                .map_or(Ok(serde_json::Value::Null), stat_value_to_json_value),
        }
    }

    #[allow(clippy::cast_precision_loss)]
    fn aggregate_numeric_value(&self, value: &StatValue) -> Result<f64> {
        let numeric = stat_value_to_f64(value)?;
        self.argument_offset.map_or(Ok(numeric), |offset| {
            let adjusted = numeric + offset as f64;
            if adjusted.is_finite() {
                Ok(adjusted)
            } else {
                Err(ShardLoomError::InvalidOperation(
                    "local Vortex simple aggregate argument offset produced a non-finite value; no fallback execution was attempted"
                        .to_string(),
                ))
            }
        })
    }
}

#[cfg(feature = "vortex-local-primitives")]
#[allow(clippy::cast_precision_loss)]
fn simple_average_value(sum: f64, count: u64) -> f64 {
    sum / count as f64
}

#[cfg(feature = "vortex-local-primitives")]
fn simple_aggregate_min_value(current: Option<StatValue>, value: &StatValue) -> Result<StatValue> {
    let Some(current) = current else {
        return Ok(value.clone());
    };
    match stat_value_cmp(value, &current) {
        Some(std::cmp::Ordering::Less) => Ok(value.clone()),
        Some(_) => Ok(current),
        None => Err(ShardLoomError::InvalidOperation(
            "local Vortex simple aggregate min encountered incomparable values; no fallback execution was attempted"
                .to_string(),
        )),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn simple_aggregate_max_value(current: Option<StatValue>, value: &StatValue) -> Result<StatValue> {
    let Some(current) = current else {
        return Ok(value.clone());
    };
    match stat_value_cmp(value, &current) {
        Some(std::cmp::Ordering::Greater) => Ok(value.clone()),
        Some(_) => Ok(current),
        None => Err(ShardLoomError::InvalidOperation(
            "local Vortex simple aggregate max encountered incomparable values; no fallback execution was attempted"
                .to_string(),
        )),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn json_number_from_f64(value: f64) -> Result<serde_json::Value> {
    serde_json::Number::from_f64(value)
        .map(serde_json::Value::Number)
        .ok_or_else(|| {
            ShardLoomError::InvalidOperation(
                "local Vortex simple aggregate cannot serialize non-finite numeric result; no fallback execution was attempted"
                    .to_string(),
            )
        })
}

#[cfg(feature = "vortex-local-primitives")]
fn deterministic_sample_score(seed: u64, row_index: usize) -> u64 {
    let row = u64::try_from(row_index).map_or(u64::MAX, |value| value);
    let mut value = seed ^ row.wrapping_mul(0x9e37_79b9_7f4a_7c15);
    value = value.wrapping_add(0x9e37_79b9_7f4a_7c15);
    value = (value ^ (value >> 30)).wrapping_mul(0xbf58_476d_1ce4_e5b9);
    value = (value ^ (value >> 27)).wrapping_mul(0x94d0_49bb_1331_11eb);
    value ^ (value >> 31)
}

#[cfg(feature = "vortex-local-primitives")]
fn projection_scan_plan(
    dtype: &vortex::array::dtype::DType,
    projection: &ProjectionRequest,
    primitive_kind: VortexQueryPrimitiveKind,
) -> Result<LocalVortexScanPlan> {
    use vortex::array::expr::{root, select};

    let projected_columns = projected_column_names(dtype, projection, primitive_kind)?;
    let projection_expr = if dtype.is_primitive() {
        None
    } else {
        let field_names = projected_columns
            .iter()
            .map(String::as_str)
            .collect::<Vec<_>>();
        Some(select(field_names, root()))
    };
    Ok(LocalVortexScanPlan {
        filter: None,
        residual_predicate: None,
        projection: projection_expr,
        projected_columns: projected_columns.clone(),
        output_columns: Some(projected_columns),
        source_order_limit: None,
        embedded_derived_column_rewrites: Vec::new(),
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn projection_request_from_declared_columns(
    declared_columns: &[String],
) -> Result<ProjectionRequest> {
    declared_columns
        .iter()
        .map(|column| ColumnRef::new(column.as_str()))
        .collect::<Result<Vec<_>>>()
        .map(ProjectionRequest::columns)
}

#[cfg(feature = "vortex-local-primitives")]
fn sort_rows_source_row_id_projection_expr(
    projected_columns: &[String],
) -> Result<vortex::array::expr::Expression> {
    use vortex::array::dtype::Nullability;
    use vortex::array::expr::{col, pack};
    use vortex::layout::layouts::row_idx::row_idx;

    if projected_columns
        .iter()
        .any(|column| column == SHARDLOOM_SOURCE_ROW_ID_COLUMN)
    {
        return Err(ShardLoomError::InvalidOperation(format!(
            "local Vortex sort cannot reserve internal row-id projection column '{SHARDLOOM_SOURCE_ROW_ID_COLUMN}' because the source already exposes that name; no fallback execution was attempted"
        )));
    }
    let mut elements = Vec::with_capacity(projected_columns.len() + 1);
    for column in projected_columns {
        elements.push((column.clone(), col(column.clone())));
    }
    elements.push((SHARDLOOM_SOURCE_ROW_ID_COLUMN.to_string(), row_idx()));
    Ok(pack(elements, Nullability::NonNullable))
}

#[cfg(feature = "vortex-local-primitives")]
fn attach_predicate_to_scan_plan(
    plan: &mut LocalVortexScanPlan,
    predicate: &PredicateExpr,
    dtype: &vortex::array::dtype::DType,
    primitive_kind: VortexQueryPrimitiveKind,
) -> Result<PredicateExpr> {
    let rewrite = rewrite_predicate_for_embedded_derived_columns_with_evidence(
        dtype,
        primitive_kind,
        predicate,
    )?;
    plan.embedded_derived_column_rewrites
        .clone_from(&rewrite.rewritten_columns);
    let predicate = rewrite.predicate;
    let (pushdown_predicate, residual_predicate) =
        split_predicate_for_vortex_pushdown(&predicate, primitive_kind);
    if let Some(residual_predicate) = residual_predicate {
        use vortex::array::expr::{root, select};

        plan.residual_predicate = Some(residual_predicate.clone());
        let mut projected_columns = plan
            .projected_columns
            .iter()
            .map(ColumnRef::new)
            .collect::<Result<Vec<_>>>()?;
        append_predicate_columns(&residual_predicate, &mut projected_columns);
        let projected_column_names = projected_columns
            .into_iter()
            .map(|column| column.as_str().to_string())
            .collect::<Vec<_>>();
        plan.projection = if dtype.is_primitive() {
            None
        } else {
            let field_names = projected_column_names
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>();
            Some(select(field_names, root()))
        };
        plan.projected_columns = projected_column_names;
        if plan.output_columns.is_none() {
            plan.output_columns = Some(Vec::new());
        }
    }
    if let Some(pushdown_predicate) = pushdown_predicate {
        plan.filter = Some(predicate_to_vortex_expr(
            &pushdown_predicate,
            dtype,
            primitive_kind,
        )?);
    }
    Ok(predicate)
}

#[cfg(feature = "vortex-local-primitives")]
fn project_count_where_predicate_columns(
    plan: &mut LocalVortexScanPlan,
    predicate: &PredicateExpr,
    dtype: &vortex::array::dtype::DType,
) {
    use vortex::array::expr::{root, select};

    if dtype.is_primitive()
        || plan.residual_predicate.is_some()
        || plan.projection.is_some()
        || !plan.projected_columns.is_empty()
    {
        return;
    }

    let mut projected_columns = Vec::new();
    append_predicate_columns(predicate, &mut projected_columns);
    if projected_columns.is_empty() {
        return;
    }
    let projected_column_names = projected_columns
        .into_iter()
        .map(|column| column.as_str().to_string())
        .collect::<Vec<_>>();
    let field_names = projected_column_names
        .iter()
        .map(String::as_str)
        .collect::<Vec<_>>();
    plan.projection = Some(select(field_names, root()));
    plan.projected_columns = projected_column_names;
    plan.output_columns = Some(Vec::new());
}

#[cfg(feature = "vortex-local-primitives")]
fn sample_scan_plan(
    dtype: &vortex::array::dtype::DType,
    request: &VortexQueryPrimitiveRequest,
) -> Result<LocalVortexScanPlan> {
    let mut projected_columns = sample_output_columns(dtype, request)?
        .iter()
        .map(ColumnRef::new)
        .collect::<Result<Vec<_>>>()?;
    if let Some(column) = request.sample_weight_column.as_ref() {
        append_unique_column(&mut projected_columns, column);
    }
    let projection = ProjectionRequest::columns(projected_columns);
    let mut plan = projection_scan_plan(dtype, &projection, request.kind)?;
    if let Some(predicate) = request.predicate.as_ref() {
        attach_predicate_to_scan_plan(&mut plan, predicate, dtype, request.kind)?;
    }
    plan.source_order_limit = request.source_order_limit;
    Ok(plan)
}

#[cfg(feature = "vortex-local-primitives")]
fn sample_output_columns(
    dtype: &vortex::array::dtype::DType,
    request: &VortexQueryPrimitiveRequest,
) -> Result<Vec<String>> {
    projected_column_names(dtype, &request.projection, request.kind)
}

#[cfg(feature = "vortex-local-primitives")]
fn row_export_columns_for_output_and_residual(
    output_columns: &[String],
    residual_predicate: Option<&PredicateExpr>,
) -> Result<Vec<String>> {
    let mut columns = output_columns
        .iter()
        .map(|column| ColumnRef::new(column.as_str()))
        .collect::<Result<Vec<_>>>()?;
    if let Some(predicate) = residual_predicate {
        append_predicate_columns(predicate, &mut columns);
    }
    Ok(columns
        .into_iter()
        .map(|column| column.as_str().to_string())
        .collect())
}

#[cfg(feature = "vortex-local-primitives")]
fn drop_duplicate_output_columns(
    dtype: &vortex::array::dtype::DType,
    request: &VortexQueryPrimitiveRequest,
) -> Result<Vec<String>> {
    projected_column_names(dtype, &request.projection, request.kind)
}

#[cfg(feature = "vortex-local-primitives")]
fn drop_duplicate_key_columns(
    dtype: &vortex::array::dtype::DType,
    request: &VortexQueryPrimitiveRequest,
) -> Result<Vec<String>> {
    let key_projection = request.deduplicate_key_projection.as_ref().ok_or_else(|| {
        ShardLoomError::InvalidOperation(
            "local Vortex drop_duplicates requires explicit row-key columns; no fallback execution was attempted"
                .to_string(),
        )
    })?;
    let key_columns = projected_column_names(dtype, key_projection, request.kind)?;
    if key_columns.is_empty() {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex drop_duplicates requires at least one row-key column; no fallback execution was attempted"
                .to_string(),
        ));
    }
    Ok(key_columns)
}

#[cfg(feature = "vortex-local-primitives")]
fn drop_duplicate_scan_plan(
    dtype: &vortex::array::dtype::DType,
    request: &VortexQueryPrimitiveRequest,
) -> Result<LocalVortexScanPlan> {
    let output_columns = drop_duplicate_output_columns(dtype, request)?;
    let key_columns = drop_duplicate_key_columns(dtype, request)?;
    let mut projected_columns = output_columns
        .iter()
        .map(ColumnRef::new)
        .collect::<Result<Vec<_>>>()?;
    for column in &key_columns {
        append_unique_column(&mut projected_columns, &ColumnRef::new(column)?);
    }
    let projection = ProjectionRequest::columns(projected_columns);
    let mut plan = projection_scan_plan(dtype, &projection, request.kind)?;
    if let Some(predicate) = request.predicate.as_ref() {
        attach_predicate_to_scan_plan(&mut plan, predicate, dtype, request.kind)?;
    }
    plan.source_order_limit = request.source_order_limit;
    Ok(plan)
}

#[cfg(feature = "vortex-local-primitives")]
fn projected_column_names(
    dtype: &vortex::array::dtype::DType,
    projection: &ProjectionRequest,
    primitive_kind: VortexQueryPrimitiveKind,
) -> Result<Vec<String>> {
    match projection {
        ProjectionRequest::All => local_user_field_names(dtype, primitive_kind),
        ProjectionRequest::Columns(columns) => {
            let available = local_field_names(dtype, primitive_kind)?;
            let available_set = available
                .iter()
                .map(String::as_str)
                .collect::<std::collections::BTreeSet<_>>();
            let mut out = Vec::new();
            for column in columns {
                if !available_set.contains(column.as_str()) {
                    return Err(ShardLoomError::InvalidOperation(format!(
                        "projection column '{}' was not found in local Vortex target",
                        column.as_str()
                    )));
                }
                out.push(column.as_str().to_string());
            }
            Ok(out)
        }
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn local_user_field_names(
    dtype: &vortex::array::dtype::DType,
    primitive_kind: VortexQueryPrimitiveKind,
) -> Result<Vec<String>> {
    Ok(local_field_names(dtype, primitive_kind)?
        .into_iter()
        .filter(|column| !is_shardloom_hidden_derived_column(column))
        .collect())
}

#[cfg(feature = "vortex-local-primitives")]
fn local_field_names(
    dtype: &vortex::array::dtype::DType,
    primitive_kind: VortexQueryPrimitiveKind,
) -> Result<Vec<String>> {
    use vortex::array::dtype::DType;

    match dtype {
        DType::Struct(fields, _) => Ok(fields
            .names()
            .iter()
            .map(|name| name.as_ref().to_string())
            .collect()),
        DType::Primitive(_, _) => Ok(vec!["value".to_string()]),
        other => Err(ShardLoomError::InvalidOperation(format!(
            "local primitive {} does not support top-level dtype {other:?}",
            primitive_kind.as_str()
        ))),
    }
}

#[cfg(feature = "vortex-local-primitives")]
struct AggregateEmbeddedDerivedRewrite {
    aggregate: VortexSimpleAggregateRequest,
    predicate: Option<PredicateExpr>,
    rewritten_columns: Vec<String>,
}

#[cfg(feature = "vortex-local-primitives")]
struct PredicateEmbeddedDerivedRewrite {
    predicate: PredicateExpr,
    rewritten_columns: Vec<String>,
}

#[cfg(feature = "vortex-local-primitives")]
fn rewrite_simple_aggregate_for_embedded_derived_columns(
    dtype: &vortex::array::dtype::DType,
    aggregate: &VortexSimpleAggregateRequest,
    predicate: Option<&PredicateExpr>,
) -> Result<AggregateEmbeddedDerivedRewrite> {
    let fields = local_field_names(dtype, VortexQueryPrimitiveKind::SimpleAggregate)?;
    let available = fields
        .iter()
        .map(String::as_str)
        .collect::<std::collections::BTreeSet<_>>();
    if should_preserve_transformed_dictionary_source_lane(aggregate, &available)? {
        return Ok(AggregateEmbeddedDerivedRewrite {
            aggregate: aggregate.clone(),
            predicate: predicate.cloned(),
            rewritten_columns: Vec::new(),
        });
    }
    let mut aggregate = aggregate.clone();
    let mut rewritten_columns = Vec::new();
    for expression in &mut aggregate.group_expressions {
        let transform = AggregateValueTransform::from_expression(expression)?;
        if let Some(hidden) =
            embedded_derived_column_for_transform(transform, expression.column.as_str())
            && available.contains(hidden.as_str())
        {
            expression.column = ColumnRef::new(&hidden)?;
            expression.function = "identity".to_string();
            expression.argument_offset = None;
            expression.extra_columns.clear();
            push_unique_string(&mut rewritten_columns, hidden);
        }
    }
    for measure in &mut aggregate.measures {
        let Some(column) = measure.column.as_ref() else {
            continue;
        };
        let transform =
            AggregateValueTransform::from_measure_transform(measure.value_transform.as_deref())?;
        if let Some(hidden) = embedded_derived_column_for_transform(transform, column.as_str())
            && available.contains(hidden.as_str())
        {
            measure.column = Some(ColumnRef::new(&hidden)?);
            measure.value_transform = None;
            push_unique_string(&mut rewritten_columns, hidden);
        }
    }
    let predicate = predicate
        .map(|predicate| {
            rewrite_predicate_for_embedded_derived_columns(
                predicate,
                &available,
                &mut rewritten_columns,
            )
        })
        .transpose()?;
    Ok(AggregateEmbeddedDerivedRewrite {
        aggregate,
        predicate,
        rewritten_columns,
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn should_preserve_transformed_dictionary_source_lane(
    aggregate: &VortexSimpleAggregateRequest,
    available: &std::collections::BTreeSet<&str>,
) -> Result<bool> {
    if aggregate.order_by.is_empty()
        || !aggregate.group_by.is_empty()
        || aggregate.group_expressions.len() != 1
    {
        return Ok(false);
    }
    let expression = &aggregate.group_expressions[0];
    if !expression.extra_columns.is_empty()
        || is_shardloom_hidden_derived_column(expression.column.as_str())
    {
        return Ok(false);
    }
    let group_transform = AggregateValueTransform::from_expression(expression)?;
    if !matches!(
        group_transform,
        AggregateValueTransform::Length | AggregateValueTransform::UrlDomain
    ) {
        return Ok(false);
    }
    let source_column = expression.column.as_str();
    let Some(hidden_group_column) =
        embedded_derived_column_for_transform(group_transform, source_column)
    else {
        return Ok(false);
    };
    let hidden_length_column = shardloom_utf8_length_derived_column(source_column);
    if !available.contains(hidden_group_column.as_str())
        || !available.contains(hidden_length_column.as_str())
    {
        return Ok(false);
    }

    let mut has_same_source_length_measure = false;
    for measure in &aggregate.measures {
        let function = SimpleAggregateFunction::parse(&measure.function)?;
        let value_transform =
            AggregateValueTransform::from_measure_transform(measure.value_transform.as_deref())?;
        let measure_column = measure.column.as_ref().map(ColumnRef::as_str);
        match function {
            SimpleAggregateFunction::Count => {
                if let Some(column) = measure_column
                    && (column != source_column
                        || !matches!(
                            value_transform,
                            AggregateValueTransform::Identity | AggregateValueTransform::Length
                        ))
                {
                    return Ok(false);
                }
            }
            SimpleAggregateFunction::Sum | SimpleAggregateFunction::Avg => {
                if measure_column != Some(source_column)
                    || !matches!(value_transform, AggregateValueTransform::Length)
                {
                    return Ok(false);
                }
                has_same_source_length_measure = true;
            }
            SimpleAggregateFunction::Min | SimpleAggregateFunction::Max => {
                if measure_column != Some(source_column)
                    || !matches!(
                        value_transform,
                        AggregateValueTransform::Identity | AggregateValueTransform::Length
                    )
                {
                    return Ok(false);
                }
                if matches!(value_transform, AggregateValueTransform::Length) {
                    has_same_source_length_measure = true;
                }
            }
            SimpleAggregateFunction::CountDistinct => return Ok(false),
        }
    }

    Ok(has_same_source_length_measure)
}

#[cfg(feature = "vortex-local-primitives")]
fn embedded_derived_column_for_transform(
    transform: AggregateValueTransform,
    column: &str,
) -> Option<String> {
    match transform {
        AggregateValueTransform::Length => Some(shardloom_utf8_length_derived_column(column)),
        AggregateValueTransform::UrlDomain => Some(shardloom_url_domain_derived_column(column)),
        AggregateValueTransform::ExtractMinute => {
            Some(shardloom_extract_minute_derived_column(column))
        }
        AggregateValueTransform::DateTruncMinute => {
            Some(shardloom_date_trunc_minute_derived_column(column))
        }
        AggregateValueTransform::Identity
        | AggregateValueTransform::ConstantInt(_)
        | AggregateValueTransform::AddOffset(_)
        | AggregateValueTransform::CaseSearchAdvZeroRefererElseEmpty => None,
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn rewrite_predicate_for_embedded_derived_columns(
    predicate: &PredicateExpr,
    available: &std::collections::BTreeSet<&str>,
    rewritten_columns: &mut Vec<String>,
) -> Result<PredicateExpr> {
    match predicate {
        PredicateExpr::And(predicates) => Ok(simplify_rewritten_and_predicates(
            predicates
                .iter()
                .map(|predicate| {
                    rewrite_predicate_for_embedded_derived_columns(
                        predicate,
                        available,
                        rewritten_columns,
                    )
                })
                .collect::<Result<Vec<_>>>()?,
        )),
        PredicateExpr::Compare { column, op, value } => {
            if matches!(value, StatValue::Utf8(text) if text.is_empty())
                && matches!(op, ComparisonOp::Eq | ComparisonOp::NotEq)
            {
                let hidden = shardloom_utf8_length_derived_column(column.as_str());
                if available.contains(hidden.as_str()) {
                    push_unique_string(rewritten_columns, hidden.clone());
                    return Ok(PredicateExpr::Compare {
                        column: ColumnRef::new(hidden)?,
                        op: match op {
                            ComparisonOp::Eq => ComparisonOp::Eq,
                            ComparisonOp::NotEq => ComparisonOp::Gt,
                            _ => *op,
                        },
                        value: StatValue::UInt64(0),
                    });
                }
            }
            Ok(predicate.clone())
        }
        PredicateExpr::StringContains { .. } => {
            rewrite_string_contains_for_embedded_length(predicate, available, rewritten_columns)
        }
        PredicateExpr::InList {
            values, negated, ..
        } if values.is_empty() => Ok(if *negated {
            PredicateExpr::AlwaysTrue
        } else {
            PredicateExpr::AlwaysFalse
        }),
        PredicateExpr::InList {
            column,
            values,
            negated,
        } if values.len() == 1 => match (&values[0], negated) {
            (StatValue::Null, false) => Ok(PredicateExpr::IsNull {
                column: column.clone(),
            }),
            (StatValue::Null, true) => Ok(PredicateExpr::IsNotNull {
                column: column.clone(),
            }),
            (value, false) => Ok(PredicateExpr::Compare {
                column: column.clone(),
                op: ComparisonOp::Eq,
                value: value.clone(),
            }),
            (_, true) => Ok(predicate.clone()),
        },
        PredicateExpr::AlwaysTrue
        | PredicateExpr::AlwaysFalse
        | PredicateExpr::IsNull { .. }
        | PredicateExpr::IsNotNull { .. }
        | PredicateExpr::InList { .. } => Ok(predicate.clone()),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn rewrite_string_contains_for_embedded_length(
    predicate: &PredicateExpr,
    available: &std::collections::BTreeSet<&str>,
    rewritten_columns: &mut Vec<String>,
) -> Result<PredicateExpr> {
    let PredicateExpr::StringContains {
        column,
        needle,
        negated,
    } = predicate
    else {
        return Ok(predicate.clone());
    };
    if needle.is_empty() {
        return Ok(if *negated {
            PredicateExpr::AlwaysFalse
        } else {
            PredicateExpr::IsNotNull {
                column: column.clone(),
            }
        });
    }
    if *negated {
        return Ok(predicate.clone());
    }
    let hidden = shardloom_utf8_length_derived_column(column.as_str());
    if !available.contains(hidden.as_str()) {
        return Ok(predicate.clone());
    }
    let minimum_len = u64::try_from(needle.len()).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local primitive UTF-8 contains predicate length exceeded u64: {error}; no fallback execution was attempted"
        ))
    })?;
    push_unique_string(rewritten_columns, hidden.clone());
    Ok(simplify_rewritten_and_predicates(vec![
        PredicateExpr::Compare {
            column: ColumnRef::new(hidden)?,
            op: ComparisonOp::GtEq,
            value: StatValue::UInt64(minimum_len),
        },
        predicate.clone(),
    ]))
}

#[cfg(feature = "vortex-local-primitives")]
fn simplify_rewritten_and_predicates(predicates: Vec<PredicateExpr>) -> PredicateExpr {
    let mut simplified = Vec::new();
    for predicate in predicates {
        match predicate {
            PredicateExpr::AlwaysFalse => return PredicateExpr::AlwaysFalse,
            PredicateExpr::AlwaysTrue => {}
            PredicateExpr::And(nested) => {
                let nested = simplify_rewritten_and_predicates(nested);
                match nested {
                    PredicateExpr::AlwaysFalse => return PredicateExpr::AlwaysFalse,
                    PredicateExpr::AlwaysTrue => {}
                    predicate => simplified.push(predicate),
                }
            }
            predicate => simplified.push(predicate),
        }
    }
    match simplified.len() {
        0 => PredicateExpr::AlwaysTrue,
        1 => simplified.pop().expect("checked length"),
        _ => PredicateExpr::And(simplified),
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn rewrite_predicate_for_embedded_derived_columns_with_evidence(
    dtype: &vortex::array::dtype::DType,
    primitive_kind: VortexQueryPrimitiveKind,
    predicate: &PredicateExpr,
) -> Result<PredicateEmbeddedDerivedRewrite> {
    let fields = local_field_names(dtype, primitive_kind)?;
    let available = fields
        .iter()
        .map(String::as_str)
        .collect::<std::collections::BTreeSet<_>>();
    let mut rewritten_columns = Vec::new();
    let predicate = rewrite_predicate_for_embedded_derived_columns(
        predicate,
        &available,
        &mut rewritten_columns,
    )?;
    Ok(PredicateEmbeddedDerivedRewrite {
        predicate,
        rewritten_columns,
    })
}

#[cfg(feature = "vortex-local-primitives")]
fn annotate_simple_aggregate_rewrite_summary(
    summary: &mut String,
    rewrite: &AggregateEmbeddedDerivedRewrite,
) -> Result<()> {
    annotate_embedded_derived_column_rewrite_summary(summary, &rewrite.rewritten_columns)
}

#[cfg(feature = "vortex-local-primitives")]
fn annotate_embedded_derived_column_rewrite_summary(
    summary: &mut String,
    rewritten_columns: &[String],
) -> Result<()> {
    if rewritten_columns.is_empty() {
        return Ok(());
    }
    let mut payload = serde_json::from_str::<serde_json::Value>(summary).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex embedded rewrite evidence could not parse result summary: {error}; no fallback execution was attempted"
        ))
    })?;
    let serde_json::Value::Object(object) = &mut payload else {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex embedded rewrite evidence requires JSON object result summary; no fallback execution was attempted"
                .to_string(),
        ));
    };
    object.insert(
        "embedded_derived_column_rewrite_status".to_string(),
        serde_json::Value::String("applied".to_string()),
    );
    object.insert(
        "embedded_derived_column_rewrites".to_string(),
        serde_json::Value::Array(
            rewritten_columns
                .iter()
                .cloned()
                .map(serde_json::Value::String)
                .collect(),
        ),
    );
    *summary = serde_json::to_string(&payload).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex embedded rewrite evidence could not serialize result summary: {error}; no fallback execution was attempted"
        ))
    })?;
    Ok(())
}

#[cfg(feature = "vortex-local-primitives")]
fn annotate_simple_aggregate_layout_correlation_summary(
    summary: &mut String,
    embedded_layout: &VortexLocalPrimitiveEmbeddedLayoutReport,
) -> Result<()> {
    let mut payload = serde_json::from_str::<serde_json::Value>(summary).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex simple aggregate layout/accessor evidence could not parse result summary: {error}; no fallback execution was attempted"
        ))
    })?;
    let serde_json::Value::Object(object) = &mut payload else {
        return Err(ShardLoomError::InvalidOperation(
            "local Vortex simple aggregate layout/accessor evidence requires JSON object result summary; no fallback execution was attempted"
                .to_string(),
        ));
    };
    let materialized_columns = object
        .get("aggregate_materialized_accessor_columns")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("none")
        .to_string();
    if materialized_columns == "none" {
        object.insert(
            "aggregate_accessor_layout_correlation_status".to_string(),
            serde_json::Value::String("not_required_no_materialized_accessors".to_string()),
        );
        object.insert(
            "aggregate_accessor_layout_correlation_columns".to_string(),
            serde_json::Value::String("none".to_string()),
        );
        object.insert(
            "aggregate_accessor_layout_correlation_blockers".to_string(),
            serde_json::Value::String("none".to_string()),
        );
        insert_aggregate_accessor_layout_metadata_fields(object, embedded_layout);
        *summary = serde_json::to_string(&payload).map_err(|error| {
            ShardLoomError::InvalidOperation(format!(
                "local Vortex simple aggregate layout/accessor evidence could not serialize result summary: {error}; no fallback execution was attempted"
            ))
        })?;
        return Ok(());
    }

    let lower_encoding_inventory = embedded_layout
        .layout_encoding_inventory
        .to_ascii_lowercase();
    let layout_dictionary_present = embedded_layout
        .domain_dictionary_status
        .contains("dictionary_layout_present")
        || lower_encoding_inventory.contains("dict")
        || lower_encoding_inventory.contains("dictionary");
    let string_encoding_layout_present = lower_encoding_inventory.contains("fsst")
        || lower_encoding_inventory.contains("utf8")
        || lower_encoding_inventory.contains("varbin")
        || lower_encoding_inventory.contains("string");
    let string_domain_present = embedded_layout
        .domain_dictionary_status
        .contains("utf8_domain_columns_present");
    let status = if layout_dictionary_present {
        "artifact_dictionary_layout_present_accessor_materialized"
    } else if string_encoding_layout_present {
        "artifact_string_encoding_layout_present_accessor_materialized"
    } else if string_domain_present {
        "artifact_string_domain_present_dictionary_layout_not_observed"
    } else if embedded_layout.metadata_persisted_in_artifact {
        "artifact_layout_present_accessor_materialized_no_dictionary_signal"
    } else {
        "artifact_layout_unavailable_accessor_materialized"
    };
    object.insert(
        "aggregate_accessor_layout_correlation_status".to_string(),
        serde_json::Value::String(status.to_string()),
    );
    object.insert(
        "aggregate_accessor_layout_correlation_columns".to_string(),
        serde_json::Value::String(materialized_columns),
    );
    object.insert(
        "aggregate_accessor_layout_correlation_blockers".to_string(),
        object
            .get("aggregate_accessor_blockers")
            .cloned()
            .unwrap_or_else(|| serde_json::Value::String("none".to_string())),
    );
    insert_aggregate_accessor_layout_metadata_fields(object, embedded_layout);
    *summary = serde_json::to_string(&payload).map_err(|error| {
        ShardLoomError::InvalidOperation(format!(
            "local Vortex simple aggregate layout/accessor evidence could not serialize result summary: {error}; no fallback execution was attempted"
        ))
    })?;
    Ok(())
}

#[cfg(feature = "vortex-local-primitives")]
fn insert_aggregate_accessor_layout_metadata_fields(
    object: &mut serde_json::Map<String, serde_json::Value>,
    embedded_layout: &VortexLocalPrimitiveEmbeddedLayoutReport,
) {
    object.insert(
        "aggregate_accessor_layout_correlation_dictionary_status".to_string(),
        serde_json::Value::String(embedded_layout.domain_dictionary_status.clone()),
    );
    object.insert(
        "aggregate_accessor_layout_correlation_encoding_inventory".to_string(),
        serde_json::Value::String(embedded_layout.layout_encoding_inventory.clone()),
    );
    object.insert(
        "aggregate_accessor_per_column_metadata_contract".to_string(),
        serde_json::Value::String(embedded_layout.per_column_metadata_contract.clone()),
    );
    object.insert(
        "aggregate_accessor_operator_selection_metadata_status".to_string(),
        serde_json::Value::String(embedded_layout.operator_selection_metadata_status.clone()),
    );
}

#[cfg(feature = "vortex-local-primitives")]
fn push_unique_string(values: &mut Vec<String>, value: String) {
    if !values.iter().any(|existing| existing == &value) {
        values.push(value);
    }
}

#[cfg(feature = "vortex-local-primitives")]
fn is_shardloom_hidden_derived_column(column: &str) -> bool {
    column.starts_with("__shardloom_derived_")
}

#[cfg(feature = "vortex-local-primitives")]
