    #[test]
    fn non_null_utf8_dictionary_match_count_shortcuts_preserve_masks() {
        use vortex::mask::Mask;

        let row_ids = vec![0, 1, 0, 2, 1, 0];
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags(
                &row_ids,
                &[false, false, false],
                "test none",
            )
            .expect("none count"),
            0
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags(
                &row_ids,
                &[true, true, true],
                "test all",
            )
            .expect("all count"),
            row_ids.len()
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags(
                &row_ids,
                &[true, false, true],
                "test mixed",
            )
            .expect("mixed count"),
            4
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags(
                &row_ids,
                &[false, false, false],
                "test none indices",
            )
            .expect("none indices"),
            Vec::<usize>::new()
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags(
                &row_ids,
                &[true, true, true],
                "test all indices",
            )
            .expect("all indices"),
            vec![0, 1, 2, 3, 4, 5]
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags(
                &row_ids,
                &[true, false, true],
                "test mixed indices",
            )
            .expect("mixed indices"),
            vec![0, 2, 3, 5]
        );

        let mask = Mask::from_iter([true, false, true, true, false, false]);
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags_masked(
                &row_ids,
                &[false, false, false],
                &mask,
                "test masked none",
            )
            .expect("masked none"),
            0
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags_masked(
                &row_ids,
                &[true, true, true],
                &mask,
                "test masked all",
            )
            .expect("masked all"),
            3
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags_masked(
                &row_ids,
                &[true, false, true],
                &mask,
                "test masked mixed",
            )
            .expect("masked mixed"),
            3
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags_masked(
                &row_ids,
                &[false, false, false],
                &mask,
                "test masked none indices",
            )
            .expect("masked none indices"),
            Vec::<usize>::new()
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags_masked(
                &row_ids,
                &[true, true, true],
                &mask,
                "test masked all indices",
            )
            .expect("masked all indices"),
            vec![0, 1, 2]
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags_masked(
                &row_ids,
                &[true, false, true],
                &mask,
                "test masked mixed indices",
            )
            .expect("masked mixed indices"),
            vec![0, 1, 2]
        );

        let all_true_mask = Mask::new_true(row_ids.len());
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags_masked(
                &row_ids,
                &[true, false, true],
                &all_true_mask,
                "test all-true mask count",
            )
            .expect("all-true mask count"),
            4
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags_masked(
                &row_ids,
                &[true, false, true],
                &all_true_mask,
                "test all-true mask indices",
            )
            .expect("all-true mask indices"),
            vec![0, 2, 3, 5]
        );

        let all_false_mask = Mask::new_false(row_ids.len());
        assert_eq!(
            fast_non_null_utf8_dictionary_match_count_from_flags_masked(
                &row_ids,
                &[true, true, true],
                &all_false_mask,
                "test all-false mask count",
            )
            .expect("all-false mask count"),
            0
        );
        assert_eq!(
            fast_non_null_utf8_dictionary_row_indices_from_match_flags_masked(
                &row_ids,
                &[true, true, true],
                &all_false_mask,
                "test all-false mask indices",
            )
            .expect("all-false mask indices"),
            Vec::<usize>::new()
        );
    }

